terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC that will be associated with the zone during creation (Required for Private Zones)
resource "aws_vpc" "primary" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "primary-vpc"
  }
}

# 2. Create a secondary VPC to demonstrate the association resource
resource "aws_vpc" "secondary" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "secondary-vpc"
  }
}

# 3. Create a Route 53 Private Hosted Zone
# Note: A private zone must be associated with at least one VPC at creation time.
resource "aws_route53_zone" "private" {
  name = "internal.example.com"

  vpc {
    vpc_id = aws_vpc.primary.id
  }
}

# 4. Use the aws_route53_zone_association resource to associate an additional VPC
# This is used to share the zone across multiple VPCs.
resource "aws_route53_zone_association" "secondary_association" {
  zone_id = aws_route53_zone.private.zone_id
  vpc_id  = aws_vpc.secondary.id
}

