  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "main-subnet-group"
  }
}

# Internal RDS Instance
resource "aws_db_instance" "internal" {
  identifier           = "internal"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  db_name              = "internal_db"
  username             = "admin"
  password             = "password123" # Should be managed via Secrets Manager in production
  db_subnet_group_name = aws_db_subnet_group.main.name
  publicly_accessible  = false
  skip_final_snapshot  = true
}

# Publicly Accessible RDS Instance
resource "aws_db_instance" "public" {
  identifier           = "public"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  db_name              = "public_db"
  username             = "admin"
  password             = "password123" # Should be managed via Secrets Manager in production
  db_subnet_group_name = aws_db_subnet_group.main.name
  publicly_accessible  = true
  skip_final_snapshot  = true
}

# Public Route 53 Hosted Zone
resource "aws_route53_zone" "public" {
  name = "database.example.com"

  tags = {
    Name = "public"
  }
}

# Private Route 53 Hosted Zone (Split-Horizon)
resource "aws_route53_zone" "private" {
  name = "database.example.com"

  vpc {
    vpc_id = aws_vpc.main.id
  }

  tags = {
    Name = "private"
  }
}

# DNS Record for External Users (Public Zone)
resource "aws_route53_record" "external_record" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "db.database.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_db_instance.public.address]
}

# DNS Record for Internal Users (Private Zone)
resource "aws_route53_record" "internal_record" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db.database.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_db_instance.internal.address]
}

