# Terraform Configuration for Multi-Region Elastic Beanstalk with Geolocation Routing

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Providers for different regions
provider "aws" {
  alias  = "us_west"
  region = "us-west-2"
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1"
}

# Variables
variable "domain_name" {
  description = "The root domain name for Route53"
  default     = "example.com"
}

# 1. Create Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "multi-region-app"
  description = "Multi-region application with Geolocation routing"
}

# 2. IAM Resources for Elastic Beanstalk Instances
resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "aws-elasticbeanstalk-ec2-role-multi-region"
  role = aws_iam_role.eb_role.name
}

resource "aws_iam_role" "eb_role" {
  name = "aws-elasticbeanstalk-ec2-role-multi-region"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "web_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# 3. Provision Elastic Beanstalk Environment in US-West-2
resource "aws_elastic_beanstalk_environment" "us_west" {
  provider            = aws.us_west
  name                = "us-west"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }
}

# 4. Provision Elastic Beanstalk Environment in EU-Central-1
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider            = aws.eu_central
  name                = "eu-central"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }
}

# 5. Route53 Configuration
resource "aws_route53_zone" "main" {
  name = var.domain_name
}

# Geolocation Record for North America -> US West Environment
resource "aws_route53_record" "us_geo" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.${var.domain_name}"
  type    = "CNAME"
  ttl     = 300

  set_identifier = "us-west-geo"
  geolocation_routing_policy {
    continent = "NA"
  }

  records = [aws_elastic_beanstalk_environment.us_west.cname]
}

# Geolocation Record for Europe -> EU Central Environment
resource "aws_route53_record" "eu_geo" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.${var.domain_name}"
  type    = "CNAME"
  ttl     = 300

  set_identifier = "eu-central-geo"
  geolocation_routing_policy {
    continent = "EU"
  }

  records = [aws_elastic_beanstalk_environment.eu_central.cname]
}

# Default Geolocation Record (Catch-all)
resource "aws_route53_record" "default_geo" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.${var.domain_name}"
  type    = "CNAME"
  ttl     = 300

  set_identifier = "default-geo"
  geolocation_routing_policy {
    country = "*"
  }

  records = [aws_elastic_beanstalk_environment.us_west.cname]
}

