terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. RDS Database Configuration
resource "aws_db_instance" "database" {
  allocated_storage         = 20
  identifier                = "my-db-instance" # Resource identifier
  db_name                   = "my_db"          # Database name requested
  engine                    = "postgres"
  engine_version            = "14"
  instance_class            = "db.t3.micro"
  username                  = "dbadmin"
  password                  = "SecurePassword123!" # Recommended: use secrets manager
  skip_final_snapshot       = false
  final_snapshot_identifier = "my-db-final-snapshot"
  backup_retention_period   = 7
  vpc_security_group_ids    = [aws_security_group.rds_sg.id]
}

# 2. Pre-deployment Snapshot
# This resource creates a snapshot of the database. 
# Using timestamp ensures a new snapshot is tracked/created prior to environment updates.
resource "aws_db_snapshot" "pre_deploy" {
  db_instance_identifier = aws_db_instance.database.identifier
  db_snapshot_identifier = "my-db-snap-${formatdate("YYYYMMDDhhmmss", timestamp())}"
}

# 3. IAM Instance Profile for Elastic Beanstalk
resource "aws_iam_role" "eb_role" {
  name = "ec2_eb_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_profile" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.eb_role.name
}

# 4. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-blue-green-app"
  description = "Application for Blue/Green deployment"
}

# Shared Environment Settings
locals {
  common_settings = [
    {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_profile.name
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DATABASE_URL"
      value     = aws_db_instance.database.endpoint
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DATABASE_NAME"
      value     = aws_db_instance.database.db_name
    }
  ]
}

# 5. Blue Environment (Production)
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "env-blue"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v6.1.2 running Node.js 20"
  cname_prefix        = "my-app-prod-blue"

  dynamic "setting" {
    for_each = local.common_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

# 6. Green Environment (Staging)
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "env-green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v6.1.2 running Node.js 20"
  cname_prefix        = "my-app-prod-green"

  dynamic "setting" {
    for_each = local.common_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

# 7. Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "allow_eb_to_rds"
  description = "Allow traffic from EB environments to RDS"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict to VPC CIDR or EB Security Group
  }
}

