provider "aws" {
  region = "us-east-1"
}

# Resource for the Reverse DNS Hosted Zone
# Reverse zones typically follow the format: [subnet-in-reverse].in-addr.arpa
resource "aws_route53_zone" "reverse_zone" {
  name = "0.0.10.in-addr.arpa"

  comment = "Reverse DNS zone for 10.0.0.0/24"
}

# Resource for the PTR (Pointer) Record
# This maps the IP address (e.g., 10.0.0.1) to the domain name
resource "aws_route53_record" "ptr_record" {
  zone_id = aws_route53_zone.reverse_zone.zone_id
  name    = "1.0.0.10.in-addr.arpa" # This represents the IP 10.0.0.1
  type    = "PTR"
  ttl     = 300
  records = ["host.example53.com"]
}

