provider "aws" {
  region = "us-east-1"
}

# --- IAM Resources for Elastic Beanstalk ---

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_worker_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "eb_multicontainer" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile1"
  role = aws_iam_role.eb_ec2_role.name
}

# --- RDS Database Instance ---

resource "aws_db_instance" "myapp_db" {
  identifier           = "myapp-db-instance"
  allocated_storage    = 20
  db_name              = "myapp_db"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "yoursecurepassword" # Use a secret manager in production
  parameter_group_name = "default.postgres15"
  skip_final_snapshot  = true
  publicly_accessible  = false
}

# --- Elastic Beanstalk Configuration ---

resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-application"
  description = "Application for myenv"
}

resource "aws_elastic_beanstalk_environment" "env" {
  name                = "myenv"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.1 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOSTNAME"
    value     = aws_db_instance.myapp_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = aws_db_instance.myapp_db.db_name
  }
}

# --- Route 53 Resources ---

resource "aws_route53_zone" "primary" {
  name = "example.com" # Replace with your domain
}

resource "aws_route53_record" "eb_alias" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.env.cname
    # Regional EB Hosted Zone ID for us-east-1
    zone_id                = "Z2AKZ3STAFDE6R" 
    evaluate_target_health = true
  }
}

output "eb_cname" {
  value = aws_elastic_beanstalk_environment.env.cname
}

output "rds_endpoint" {
  value = aws_db_instance.myapp_db.endpoint
}

