# Terraform configuration for an AWS Elastic Beanstalk Application and Environment

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define the Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "tfa_app" {
  name        = "my-terraform-app"
  description = "Managed by TerraformAI"

  appversion_lifecycle {
    service_role          = aws_iam_role.beanstalk_service_role.arn
    max_count             = 128
    delete_source_from_s3 = true
  }
}

# 2. Define the Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "tfa_env" {
  name                = "my-terraform-env"
  application         = aws_elastic_beanstalk_application.tfa_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.1 running Python 3.11"

  # IAM Instance Profile for the EC2 instances
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.beanstalk_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.beanstalk_service_role.name
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = "vpc-xxxxxxxx" # Replace with your VPC ID
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }
}

# 3. IAM Role for EC2 Instances
resource "aws_iam_role" "beanstalk_ec2_role" {
  name = "beanstalk-ec2-role"

