provider "aws" {
  region = "us-east-1"
}

# IAM Role for Elastic Beanstalk Service to manage lifecycle events
resource "aws_iam_role" "beanstalk_service_role" {
  name = "elastic-beanstalk-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
        Condition = {
          StringEquals = {
            "sts:ExternalId" = "elasticbeanstalk"
          }
        }
      },
    ]
  })
}

# Attach the standard service policy to the role
resource "aws_iam_role_policy_attachment" "beanstalk_service_policy" {
  role       = aws_iam_role.beanstalk_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

# Elastic Beanstalk Application with App Version Lifecycle
resource "aws_elastic_beanstalk_application" "example_app" {
  name        = "my-beanstalk-application"
  description = "Application with automated version lifecycle management"

  appversion_lifecycle {
    service_role          = aws_iam_role.beanstalk_service_role.arn
    max_count             = 50
    delete_source_from_s3 = true
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# Output the application name
output "beanstalk_application_name" {
  value = aws_elastic_beanstalk_application.example_app.name
}

