# AWS Provider configuration
provider "aws" {
  region = "us-east-1"
}

# IAM Role for CodeBuild Service
resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild to allow logging and basic actions
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "example-codebuild-policy"
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = ["*"]
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning",
          "s3:PutObject"
        ]
      }
    ]
  })
}

# CodeBuild Project with Secondary Sources
resource "aws_codebuild_project" "example" {
  name           = "example-project-with-secondary-sources"
  description    = "An example CodeBuild project with primary and secondary sources"
  build_timeout  = 60
  service_role   = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }
  }

  # Primary Source
  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/primary-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  # Secondary Source 1: GitHub Repository
  secondary_sources {
    type              = "GITHUB"
    location          = "https://github.com/your-org/secondary-repo.git"
    source_identifier = "secondary_repo_auth"
    git_clone_depth   = 1
  }

  # Secondary Source 2: S3 Bucket
  secondary_sources {
    type              = "S3"
    location          = "example-bucket-name/path/to/source.zip"
    source_identifier = "static_assets"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}
```

