# IAM Policy for CodeBuild to access S3 and CloudWatch Logs
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.build_artifacts.arn,
          "${aws_s3_bucket.build_artifacts.arn}/*"
        ]
      }
    ]
  })
}

# AWS CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example project with primary and secondary artifacts"
  build_timeout = 5
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type                = "S3"
    location            = aws_s3_bucket.build_artifacts.bucket
    name                = "primary-output.zip"
    packaging           = "ZIP"
    encryption_disabled = false
  }

  # Secondary Artifacts definition
  secondary_artifacts {
    artifact_identifier = "docs_artifact"
    type                = "S3"
    location            = aws_s3_bucket.build_artifacts.bucket
    path                = "documentation/"
    name                = "project-docs.zip"
    packaging           = "ZIP"
  }

  secondary_artifacts {
    artifact_identifier = "binary_artifact"
    type                = "S3"
    location            = aws_s3_bucket.build_artifacts.bucket
    path                = "binaries/"
    name                = "app-binary"
    packaging           = "NONE"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_TYPE"
      value = "example"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/aws-samples/aws-codebuild-samples.git"
    git_clone_depth = 1

    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo Building...
            - mkdir output docs bin
            - touch output/main.txt docs/readme.txt bin/app.exe
      artifacts:
        files:
          - '**/*'
        base-directory: 'output'
        secondary-artifacts:
          docs_artifact:
            files:
              - 'readme.txt'
            base-directory: 'docs'
          binary_artifact:
            files:
              - 'app.exe'
            base-directory: 'bin'
    EOF
  }

  source_version = "master"

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

