resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = ["*"]
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning",
          "s3:PutObject"
        ]
      }
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Terraform managed CodeBuild project with secondary sources and artifacts"
  build_timeout = 5
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "VAR_KEY_1"
      value = "VAR_VALUE_1"
    }

    environment_variable {
      name  = "VAR_KEY_2"
      value = "VAR_VALUE_2"
      type  = "PLAINTEXT"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1

    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo Building primary source...
            - echo Secondary source content: $(ls $CODEBUILD_SRC_DIR_secondary_source)
      artifacts:
        secondary-artifacts:
          artifact1:
            files:
              - '**/*'
            base-directory: 'dist'
    EOF
  }

  secondary_sources {
    type              = "GITHUB"
    location          = "https://github.com/example/secondary-repo.git"
    source_identifier = "secondary_source"
  }

  secondary_artifacts {
    artifact_identifier = "artifact1"
    type                = "S3"
    location            = "example-bucket-name"
    path                = "build-outputs/"
    packaging           = "ZIP"
    name                = "my-secondary-artifact.zip"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "log-group"
      stream_name = "log-stream"
    }
  }

  tags = {
    Environment = "Dev"
  }
}
