  idle_session_ttl_in_seconds = 300
}

# Bot Locale
resource "aws_lexv2models_bot_locale" "pizza_locale" {
  bot_id                          = aws_lexv2models_bot.pizza_bot.id
  bot_version                     = "DRAFT"
  locale_id                       = "en_US"
  nlu_intent_confidence_threshold = 0.4
}

# Slot Type for Pizza Size
resource "aws_lexv2models_slot_type" "pizza_size" {
  name            = "PizzaSize"
  bot_id          = aws_lexv2models_bot.pizza_bot.id
  bot_version     = aws_lexv2models_bot_locale.pizza_locale.bot_version
  locale_id       = aws_lexv2models_bot_locale.pizza_locale.locale_id

  slot_type_values {
    sample_value { value = "small" }
  }
  slot_type_values {
    sample_value { value = "medium" }
  }
  slot_type_values {
    sample_value { value = "large" }
  }
  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# OrderPizza Intent
resource "aws_lexv2models_intent" "order_pizza" {
  name        = "OrderPizza"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_locale.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_locale.locale_id

  sample_utterance { utterance = "I want to order a pizza" }
  sample_utterance { utterance = "Can I get a {Size} pizza" }

  # Fulfillment configuration with a follow-up question in the closing response
  fulfillment_code_hook {
    enabled = false
  }

  closing_setting {
    active = true
    next_step {
      dialog_action {
        type = "EndConversation"
      }
    }
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Great, I've placed your order for a {Size} pizza. Would you like to add a side of garlic bread to that?"
          }
        }
      }
    }
  }
}

# Slot for Pizza Size
resource "aws_lexv2models_slot" "size_slot" {
  name        = "Size"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_locale.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_locale.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id
  slot_type_id = aws_lexv2models_slot_type.pizza_size.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What size pizza would you like? (Small, Medium, or Large)"
          }
        }
      }
    }
  }
}

# Fallback Intent (Required)
resource "aws_lexv2models_intent" "fallback" {
  name        = "FallbackIntent"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_locale.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_locale.locale_id
  parent_intent_signature = "AMAZON.FallbackIntent"
}

