provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "PizzaOrderLexBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Lex Intent for Ordering Pizza
resource "aws_lex_intent" "order_pizza_intent" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I would like to order a pizza",
    "Can I get a pizza",
    "Order a pizza"
  ]

  slot {
    name        = "PizzaSize"
    description = "The size of the pizza"
    priority    = 1
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric" # Using built-in or custom slot type

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like? (Small, Medium, or Large)"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "CrustType"
    description = "The type of crust"
    priority    = 2
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What kind of crust would you like?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Should I go ahead and order your {PizzaSize} pizza with {CrustType} crust?"
      content_type = "PlainText"
    }
    rejection_statement {
      message {
        content      = "Okay, I have cancelled your order."
        content_type = "PlainText"
      }
    }
  }

  conclusion_statement {
    message {
      content      = "Thank you! Your {PizzaSize} {CrustType} pizza has been ordered and will be delivered shortly."
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Lex Bot Configuration
resource "aws_lex_bot" "pizza_bot" {
  name                         = "PizzaOrderingBot"
  description                  = "Bot for ordering pizzas"
  process_behavior             = "BUILD"
  child_directed               = false
  locale                       = "en-US"
  idle_session_ttl_in_seconds = 300

  intent {
    intent_name    = aws_lex_intent.order_pizza_intent.name
    intent_version = "1"
  }

  abort_statement {
    message {
      content      = "I'm sorry, I'm not able to assist with that right now."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't quite catch that. Can you say that again?"
      content_type = "PlainText"
    }
  }

  depends_on = [aws_lex_intent.order_pizza_intent]
}

