# AWS Lex Bot configuration for booking a trip (using Lex V1 resources)

resource "aws_iam_role" "lex_service_role" {
  name = "LexTripBookingServiceRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_policy" {
  role       = aws_iam_role.lex_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

resource "aws_lex_intent" "book_hotel" {
  name        = "BookHotelIntent"
  description = "Intent to book a hotel room"

  sample_utterances = [
    "I would like to book a hotel",
    "Book a hotel in {Location}",
    "I want to make a reservation"
  ]

  slot {
    name                     = "Location"
    description              = "The city where the hotel is located"
    priority                 = 1
    slot_constraint          = "Required"
    slot_type                = "AMAZON.US_CITY"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "Which city will you be staying in?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name                     = "CheckInDate"
    description              = "The date of check-in"
    priority                 = 2
    slot_constraint          = "Required"
    slot_type                = "AMAZON.DATE"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What day do you want to check in?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name                     = "Nights"
    description              = "Number of nights to stay"
    priority                 = 3
    slot_constraint          = "Required"
    slot_type                = "AMAZON.NUMBER"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "How many nights are you staying?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, I have you down for a {Nights} night stay in {Location} starting {CheckInDate}. Shall I book it?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your reservation request."
      content_type = "PlainText"
    }
  }

  conclusion_statement {
    message {
      content      = "Great, your hotel in {Location} is booked. Enjoy your trip!"
      content_type = "PlainText"
    }
    response_card = jsonencode({
      version = 1
      contentType = "application/vnd.amazonaws.card.generic"
      genericAttachments = [
        {
          title = "Success"
          subTitle = "Reservation confirmed"
        }
      ]
    })
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

resource "aws_lex_bot" "trip_booking_bot" {
  name                         = "TripBookingBot"
  description                  = "Bot for booking travel arrangements"
  locale                       = "en-US"
  child_directed               = false
  idle_session_ttl_in_seconds  = 300
  voice_id                     = "Salli"
  process_behavior             = "BUILD"
  detect_sentiment             = true
  create_version               = true

  abort_statement {
    message {
      content      = "I'm sorry, I'm not able to assist with that at this time."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 3
    message {
      content      = "I didn't quite catch that. Can you say that again?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.book_hotel.name
    intent_version = "$LATEST"
  }

  # Ensure IAM role is established before bot creation
  depends_on = [aws_iam_role_policy_attachment.lex_policy]
}

