  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# Lex V2 Bot Definition
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "KidPizzaBot"
  description                 = "A fun and simple pizza ordering bot for kids."
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = true # Enabled as per the "meant for kids" requirement
  }
  idle_session_ttl_in_seconds = 300
}

# Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# Custom Slot Type for Pizza Size (Simple terms for kids)
resource "aws_lexv2models_slot_type" "size_type" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaSize"

  slot_type_values {
    sample_value { value = "big" }
  }
  slot_type_values {
    sample_value { value = "small" }
  }
  slot_type_values {
    sample_value { value = "huge" }
  }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# Custom Slot Type for Toppings
resource "aws_lexv2models_slot_type" "topping_type" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "ToppingType"

  slot_type_values { sample_value { value = "cheese" } }
  slot_type_values { sample_value { value = "pepperoni" } }
  slot_type_values { sample_value { value = "sausage" } }
  slot_type_values { sample_value { value = "extra cheese" } }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# Intent: OrderPizza
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want a yummy pizza" }
  sample_utterance { utterance = "Can I have pizza please" }
  sample_utterance { utterance = "Hungry for pizza" }
  sample_utterance { utterance = "I want to order a pizza" }

  # Closing response to confirm order
  fulfillment_code_hook {
    enabled = false # Set to true if linking to a Lambda
  }

  intent_closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Yay! Your yummy {Size} pizza with {Topping} is being made right now. It will be ready for your tummy soon!"
          }
        }
      }
    }
  }
}

# Slot: Pizza Size
resource "aws_lexv2models_slot" "size_slot" {
  bot_id       = aws_lexv2models_bot.pizza_bot.id
  bot_version  = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id    = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id    = aws_lexv2models_intent.order_pizza.intent_id
  name         = "Size"
  slot_type_id = aws_lexv2models_slot_type.size_type.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 3
      message_group {
        message {
          plain_text_message {
            value = "Do you want a big pizza, or a small pizza?"
          }
        }
      }
    }
  }
}

# Slot: Topping
resource "aws_lexv2models_slot" "topping_slot" {
  bot_id       = aws_lexv2models_bot.pizza_bot.id
  bot_version  = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id    = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id    = aws_lexv2models_intent.order_pizza.intent_id
  name         = "Topping"
  slot_type_id = aws_lexv2models_slot_type.topping_type.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 3
      message_group {
        message {
          plain_text_message {
            value = "What yummy things should we put on top? Cheese, pepperoni, or sausage?"
          }
        }
      }
    }
  }
}

# Bot Alias for deployment
resource "aws_lexv2models_bot_alias" "test_alias" {
  name        = "TestAlias"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT" # Using DRAFT for development

  sentiment_analysis_settings {
    detect_sentiment = true
  }
}

