provider "aws" {
  region = "us-east-1"
}

# IAM Role for the Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "PizzaOrderingBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      },
    ]
  })
}

# AWS Lex V2 Bot Definition
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  description                 = "Bot for ordering pizzas"
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_bot_role.arn

  data_privacy {
    child_directed = false
  }
}

# Bot Locale configuration including the NLU confidence threshold
resource "aws_lexv2models_bot_locale" "pizza_bot_en_us" {
  bot_id                          = aws_lexv2models_bot.pizza_bot.id
  bot_version                     = "DRAFT"
  locale_id                       = "en_US"
  nlu_intent_confidence_threshold = 0.5

  description = "English locale for Pizza Bot"
}

# Intent for ordering pizza
resource "aws_lexv2models_intent" "order_pizza_intent" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_en_us.locale_id
  name        = "OrderPizza"

  sample_utterance {
    utterance = "I would like to order a pizza"
  }
  sample_utterance {
    utterance = "Can I get a pizza?"
  }
  sample_utterance {
    utterance = "Order a pizza"
  }

  initial_response_setting {
    code_hook {
      active = false
    }
  }
}

# Example slot for Pizza Size
resource "aws_lexv2models_slot" "pizza_size_slot" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.pizza_bot_en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza_intent.intent_id
  name        = "PizzaSize"

  # Using a built-in slot type for simplicity
  slot_type_id = "AMAZON.AlphaNumeric" 

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 3
      message_group {
        message {
          plain_text_message {
            value = "What size pizza would you like (Small, Medium, or Large)?"
          }
        }
      }
    }
  }
}
