# IAM Role for Amazon Lex V2 Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-v2-children-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# Amazon Lex V2 Bot configured for children (COPPA compliance)
resource "aws_lexv2models_bot" "children_bot" {
  name                        = "ChildrensEducationalBot"
  description                 = "A bot designed for children with child_directed privacy settings enabled."
  role_arn                    = aws_iam_role.lex_bot_role.arn
  idle_session_ttl_in_seconds = 300

  # IMPORTANT: This setting is required for bots directed at children under 13
  data_privacy {
    child_directed = true
  }

  tags = {
    Environment = "Production"
    Audience    = "Children"
  }
}

# Create a Locale for the Bot (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                          = aws_lexv2models_bot.children_bot.id
  bot_version                     = "DRAFT"
  locale_id                       = "en_US"
  nlu_intent_confidence_threshold = 0.40

  voice_settings {
    voice_id = "Ivy" # A child-like voice from Amazon Polly
    engine   = "neural"
  }
}

# Add a default 'FallbackIntent' to the locale
resource "aws_lexv2models_intent" "fallback" {
  bot_id      = aws_lexv2models_bot.children_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"
}

# Create a Bot Version
resource "aws_lexv2models_bot_version" "v1" {
  bot_id      = aws_lexv2models_bot.children_bot.id
  locale_specification = {
    (aws_lexv2models_bot_locale.en_us.locale_id) = {
      source_bot_version = "DRAFT"
    }
  }

  depends_on = [aws_lexv2models_intent.fallback]
}

# Create a Bot Alias
resource "aws_lexv2models_bot_alias" "prod" {
