# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create an Amazon Connect Instance with SAML Identity Management
resource "aws_connect_instance" "example" {
  identity_management_type = "SAML"
  inbound_calls_enabled    = true
  outbound_calls_enabled   = true
  instance_alias           = "tf-connect-saml-instance"
}

# 2. Create a simple Lex Intent required for the Bot
resource "aws_lex_intent" "example" {
  name = "OrderFlowers"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I would like to order some flowers",
    "I want to order flowers",
  ]
}

# 3. Create an Amazon Lex Bot (V1)
resource "aws_lex_bot" "example" {
  name                         = "ExampleLexBot"
  child_directed               = false
  idle_session_ttl_in_seconds  = 300
  locale                       = "en-US"

  intent {
    intent_name    = aws_lex_intent.example.name
    intent_version = "1"
  }

  # Ensure the intent is created before the bot
  depends_on = [aws_lex_intent.example]
}

# 4. Associate the Lex Bot with the SAML Connect Instance
resource "aws_connect_bot_association" "example" {
  instance_id = aws_connect_instance.example.id

  lex_bot {
    name = aws_lex_bot.example.name
    # Lex V1 bots require specifying the region, typically same as instance
    lex_region = "us-east-1" 
  }
}

