provider "aws" {
  region = "us-east-1"
}

# 1. Input Kinesis Data Stream
resource "aws_kinesis_stream" "input_stream" {
  name             = "input-data-stream"
  shard_count      = 1
  retention_period = 24
}

# 2. IAM Role for Kinesis Analytics
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Analytics to read from the stream
resource "aws_iam_role_policy" "analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:DescribeStream"
        ]
        Effect   = "Allow"
        Resource = [aws_kinesis_stream.input_stream.arn]
      }
    ]
  })
}

# 4. Kinesis Analytics Application (Legacy SQL version for basic setup)
resource "aws_kinesis_analytics_application" "analytics_app" {
  name = "example-sql-application"

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        mapping  = "$.sensor_id"
        name     = "SENSOR_ID"
        sql_type = "VARCHAR(16)"
      }
      record_columns {
        mapping  = "$.temperature"
        name     = "TEMPERATURE"
        sql_type = "DOUBLE"
      }

      record_format {
        mapping_parameters {
          json {
            record_template = "$"
          }
        }
      }
    }
  }

  code = <<EOF
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (sensor_id VARCHAR(16), temperature DOUBLE);
CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM "SENSOR_ID", "TEMPERATURE"
FROM "SOURCE_SQL_STREAM_001"
WHERE "TEMPERATURE" > 25;
EOF
}

