    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket to store the Flink application code (JAR file)
resource "aws_s3_bucket" "code_bucket" {
  bucket = "kinesis-analytics-flink-code-${random_id.id.hex}"
}

resource "random_id" "id" {
  byte_length = 4
}

# Placeholder for the Flink application JAR file
resource "aws_s3_object" "flink_jar" {
  bucket = aws_s3_bucket.code_bucket.id
  key    = "my-flink-app.jar"
  source = "path/to/your/flink-app.jar" # Path to your local JAR file
}

# IAM Role for Kinesis Analytics Service
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      },
    ]
  })
}

# Basic IAM Policy for the Kinesis Analytics Role
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.code_bucket.arn,
          "${aws_s3_bucket.code_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData",
          "logs:DescribeLogGroups",
          "logs:DescribeLogStreams",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for Application Monitoring
resource "aws_cloudwatch_log_group" "flink_log_group" {
  name = "/aws/kinesis-analytics/example-flink-app"
}

resource "aws_cloudwatch_log_stream" "flink_log_stream" {
  name           = "flink-log-stream"
  log_group_name = aws_cloudwatch_log_group.flink_log_group.name
}

# Kinesis Data Analytics V2 Application
resource "aws_kinesisanalyticsv2_application" "flink_application" {
  name                   = "example-flink-application"
  runtime_environment    = "FLINK-1_18" # Specify desired Flink version
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT" # Options: DEFAULT, CUSTOM
      }

      monitoring_configuration {
        configuration_type = "STRICT"
        metrics_level      = "APPLICATION" # Options: APPLICATION, OPERATOR, PARALLELISM, TASK
        log_level          = "INFO"
      }

      parallelism_configuration {
        auto_scaling_enabled = true
        configuration_type   = "CUSTOM"
        parallelism          = 1
        parallelism_per_kpu  = 1
      }
    }

    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.code_bucket.arn
          file_key   = aws_s3_object.flink_jar.key
        }
      }
      code_content_type = "ZIPFILE"
    }

    # Optional: Application Properties (Parameters passed to Flink)
    environment_properties {
      property_group {
        property_group_id = "ConsumerConfigProperties"
        property_map = {
          "input.stream.name" = "input-stream"
          "aws.region"        = "us-east-1"
        }
      }
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.flink_log_stream.arn
  }

  tags = {
    Environment = "Development"
    Application = "Flink"
  }
}

