```hcl
# Terraform configuration for AWS Kinesis Firehose with Redshift Destination

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for intermediate storage (Required for Redshift destination)
resource "aws_s3_bucket" "firehose_backup" {
  bucket_prefix = "firehose-redshift-backup-"
}

# 2. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_redshift_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Firehose to access S3 and Redshift
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_redshift_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect   = "Allow"
        Action   = ["redshift:DescribeClusters"]
        Resource = [aws_redshift_cluster.example.arn]
      }
    ]
  })
}

# 4. Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "firehose-redshift-cluster"
  database_name      = "dev"
  master_username    = "adminuser"
  master_password    = "MustBe8CharactersLong1"
  node_type          = "dc2.large"
  cluster_type       = "single-node"
  skip_final_snapshot = true
}

# 5. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "redshift_stream" {
  name        = "kinesis-firehose-to-redshift"
  destination = "redshift"

  redshift_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    cluster_jdbcurl    = "jdbc:redshift://${aws_redshift_cluster.example.endpoint}/${aws_redshift_cluster.example.database_name}"
    username           = "adminuser"
    password           = "MustBe8CharactersLong1"
    data_table_name    = "ingest_table"
    copy_options       = "csv" # Example copy options

    # Firehose always uses S3 as an intermediate store before loading into Redshift
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }
  }

  # Ensure Redshift and Policy are ready
  depends_on = [aws_iam_role_policy.firehose_policy]
}
```

