  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "firehose.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF
}

# IAM Policy for Firehose to access S3 and OpenSearch
resource "aws_iam_role_policy" "firehose_policy" {
  name   = "firehose_opensearch_policy"
  role   = aws_iam_role.firehose_role.id
  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "s3:AbortMultipartUpload",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:ListBucket",
        "s3:ListBucketMultipartUploads",
        "s3:PutObject"
      ],
      "Resource": [
        "${aws_s3_bucket.firehose_backup.arn}",
        "${aws_s3_bucket.firehose_backup.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": [
        "es:DescribeDomain",
        "es:DescribeDomains",
        "es:DescribeDomainConfig",
        "es:ESHttpPost",
        "es:ESHttpPut"
      ],
      "Resource": [
        "${aws_opensearch_domain.example.arn}",
        "${aws_opensearch_domain.example.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": [
        "es:ESHttpGet"
      ],
      "Resource": [
        "${aws_opensearch_domain.example.arn}/_all/_settings",
        "${aws_opensearch_domain.example.arn}/_cluster/stats",
        "${aws_opensearch_domain.example.arn}/index-name*/_mapping/type-name",
        "${aws_opensearch_domain.example.arn}/_nodes",
        "${aws_opensearch_domain.example.arn}/_nodes/*/stats",
        "${aws_opensearch_domain.example.arn}/_nodes/stats",
        "${aws_opensearch_domain.example.arn}/_stats",
        "${aws_opensearch_domain.example.arn}/index-name*/_stats"
      ]
    }
  ]
}
EOF
}

# Kinesis Firehose Delivery Stream with OpenSearch Destination
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "terraform-firehose-to-opensearch"
  destination = "opensearch"

  opensearch_destination {
    domain_arn     = aws_opensearch_domain.example.arn
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "logs"
    type_name      = "log" # Type is required but ignored in OpenSearch 2.x+
    index_rotation_period = "OneDay"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 10
      buffering_interval = 400
      compression_format = "GZIP"
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/opensearch-stream"
      log_stream_name = "DestinationDelivery"
    }
  }

  depends_on = [aws_iam_role_policy.firehose_policy]
}
