provider "aws" {
  region = "us-east-1"
}

# --- S3 Bucket for Backup/Failed Records ---
resource "aws_s3_bucket" "firehose_backup" {
  bucket_prefix = "firehose-oss-backup-"
}

# --- OpenSearch Serverless Infrastructure ---
resource "aws_opensearchserverless_security_policy" "encryption" {
  name        = "firehose-encryption-policy"
  type        = "encryption"
  description = "Encryption policy for OSS collection"
  policy = jsonencode({
    Rules = [
      {
        Resource = ["collection/firehose-collection"],
        ResourceType = "collection"
      }
    ],
    AWSOwnedKey = true
  })
}

resource "aws_opensearchserverless_security_policy" "network" {
  name        = "firehose-network-policy"
  type        = "network"
  description = "Network policy for OSS collection"
  policy = jsonencode([
    {
      Rules = [
        {
          Resource = ["collection/firehose-collection"],
          ResourceType = "collection"
        }
      ],
      AllowFromPublic = true
    }
  ])
}

resource "aws_opensearchserverless_collection" "this" {
  name       = "firehose-collection"
  type       = "SEARCH"
  depends_on = [aws_opensearchserverless_security_policy.encryption, aws_opensearchserverless_security_policy.network]
}

# --- IAM Role for Kinesis Firehose ---
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_oss_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "firehose.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_oss_policy" {
  name   = "firehose_oss_access"
  role   = aws_iam_role.firehose_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Action = [
          "aoss:APIAccessAll"
        ]
        Effect   = "Allow"
        Resource = [aws_opensearchserverless_collection.this.arn]
      },
      {
        Action = [
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = ["*"]
      }
    ]
  })
}

# --- OSS Data Access Policy (Allows Firehose to write data) ---
resource "aws_opensearchserverless_access_policy" "data_access" {
  name        = "firehose-data-access"
  type        = "data"
  description = "Allow Firehose to write to collection"
  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "index",
          Resource     = ["index/firehose-collection/*"],
          Permission   = ["aoss:CreateIndex", "aoss:DescribeIndex", "aoss:ReadDocument", "aoss:WriteDocument", "aoss:UpdateIndex"]
        },
        {
          ResourceType = "collection",
          Resource     = ["collection/firehose-collection"],
          Permission   = ["aoss:CreateCollectionItems", "aoss:DescribeCollectionItems"]
        }
      ],
      Principal = [aws_iam_role.firehose_role.arn]
    }
  ])
}

# --- Kinesis Firehose Delivery Stream ---
resource "aws_kinesis_firehose_delivery_stream" "oss_stream" {
  name        = "firehose-to-opensearch-serverless"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    collection_endpoint = aws_opensearchserverless_collection.this.collection_endpoint
    index_name          = "logs"
    role_arn            = aws_iam_role.firehose_role.arn

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      compression_format = "GZIP"
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/firehose-to-oss"
      log_stream_name = "DestinationDelivery"
    }
  }

  depends_on = [aws_opensearchserverless_access_policy.data_access]
}

