provider "aws" {
  region = "us-east-1"
}

# --- VPC Networking ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_security_group" "firehose_sg" {
  name        = "firehose-es-sg"
  description = "Security group for Firehose VPC access"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "elasticsearch_sg" {
  name        = "elasticsearch-sg"
  description = "Security group for Elasticsearch domain"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.firehose_sg.id]
  }
}

# --- Elasticsearch (OpenSearch) Domain ---

resource "aws_elasticsearch_domain" "es" {
  domain_name           = "firehose-es-domain"
  elasticsearch_version = "7.10"

  cluster_config {
    instance_type = "t3.small.elasticsearch"
  }

  vpc_options {
    subnet_ids         = [aws_subnet.private.id]
    security_group_ids = [aws_security_group.elasticsearch_sg.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  access_policies = <<POLICIES
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "AWS": "*"
      },
      "Action": "es:*",
      "Resource": "arn:aws:es:us-east-1:${data.aws_caller_identity.current.account_id}:domain/firehose-es-domain/*"
    }
  ]
}
POLICIES
}

data "aws_caller_identity" "current" {}

# --- S3 Bucket for Backup ---

resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-es-backup-bucket-${data.aws_caller_identity.current.account_id}"
}

# --- IAM Roles and Policies ---

resource "aws_iam_role" "firehose_role" {
  name = "firehose_es_delivery_role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "firehose.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_es_policy"
  role = aws_iam_role.firehose_role.id

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "s3:AbortMultipartUpload",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:ListBucket",
        "s3:ListBucketMultipartUploads",
        "s3:PutObject"
      ],
      "Resource": [
        "${aws_s3_bucket.firehose_backup.arn}",
        "${aws_s3_bucket.firehose_backup.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": [
        "es:DescribeElasticsearchDomain",
        "es:DescribeElasticsearchDomains",
        "es:DescribeElasticsearchDomainConfig",
        "es:ESHttpPost",
        "es:ESHttpPut"
      ],
      "Resource": [
        "${aws_elasticsearch_domain.es.arn}",
        "${aws_elasticsearch_domain.es.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": [
        "ec2:DescribeVpcs",
        "ec2:DescribeVpcAttribute",
        "ec2:DescribeSubnets",
        "ec2:DescribeSecurityGroups",
        "ec2:DescribeNetworkInterfaces",
        "ec2:CreateNetworkInterface",
        "ec2:CreateNetworkInterfacePermission",
        "ec2:DeleteNetworkInterface"
      ],
      "Resource": "*"
    }
  ]
}
EOF
}

# --- Kinesis Firehose Delivery Stream ---

resource "aws_kinesis_firehose_delivery_stream" "es_stream" {
  name        = "kinesis-firehose-es-stream"
  destination = "elasticsearch"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_backup.arn
  }

  elasticsearch_configuration {
    domain_arn     = aws_elasticsearch_domain.es.arn
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "logs"
    type_name      = "_doc"
    s3_backup_mode = "FailedDocumentsOnly"

    vpc_config {
      subnet_ids         = [aws_subnet.private.id]
      security_group_ids = [aws_security_group.firehose_sg.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }

    cloudwatch_logging_options {
      enabled         = false
    }
  }

  depends_on = [aws_iam_role_policy.firehose_policy]
}

