provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for failed delivery backup (Required by Firehose)
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-http-delivery-backup-bucket"
}

# IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_http_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy to allow Firehose to write to S3 backup bucket
resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      }
    ]
  })
}

# Kinesis Firehose Delivery Stream with HTTP Endpoint Destination (New Relic Example)
resource "aws_kinesis_firehose_delivery_stream" "http_endpoint_stream" {
  name        = "terraform-firehose-to-http"
  destination = "http_endpoint"

  http_endpoint_configuration {
    url                = "https://aws-api.newrelic.com/firehose/v1" # New Relic US Endpoint
    name               = "New Relic"
    access_key         = "YOUR_NEW_RELIC_LICENSE_KEY" # Replace with actual API key
    retry_duration     = 300
    buffering_size     = 5
    buffering_interval = 60
    role_arn           = aws_iam_role.firehose_role.arn

    # S3 backup configuration for failed HTTP deliveries
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    request_configuration {
      common_attributes {
        name  = "Source"
        value = "KinesisFirehose"
      }
      common_attributes {
        name  = "Environment"
        value = "Production"
      }
    }

    cloudwatch_logging_options {
      enabled         = false # Set to true and provide group/stream names for debugging
    }
  }
}

