}

# IAM Policy for Firehose to access S3
resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.destination_bucket.arn,
          "${aws_s3_bucket.destination_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Kinesis Firehose Delivery Stream with Extended S3 Configuration
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "terraform-firehose-extended-s3-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.destination_bucket.arn

    # Buffer configuration
    buffering_size     = 5
    buffering_interval = 300

    # Compression and encryption
    compression_format = "GZIP"

    # Custom prefixes for organized data storage
    prefix              = "data/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    error_output_prefix = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/!{firehose:error-output-type}/"

    # CloudWatch logging for troubleshooting
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_logs.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_s3_stream.name
    }
  }
}

# CloudWatch resources for logging
resource "aws_cloudwatch_log_group" "firehose_logs" {
  name = "/aws/kinesisfirehose/terraform-firehose-extended-s3-stream"
}

resource "aws_cloudwatch_log_stream" "firehose_s3_stream" {
  name           = "S3Delivery"
  log_group_name = aws_cloudwatch_log_group.firehose_logs.name
}
```

