# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a Kinesis Data Stream to act as the source for the Analytics Application
resource "aws_kinesis_stream" "source_stream" {
  name             = "kinesis-analytics-source-stream"
  shard_count      = 1
  retention_period = 24
}

# IAM Role for Kinesis Analytics
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      },
    ]
  })
}

# IAM Policy to allow the Analytics App to read from the source stream
resource "aws_iam_role_policy" "analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.source_stream.arn
      }
    ]
  })
}

# Amazon Kinesis Analytics Application (SQL-based)
resource "aws_kinesis_analytics_application" "sql_application" {
  name = "example-sql-analytics-app"

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.source_stream.arn
      role_arn     = aws_iam_role.analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        mapping  = "$.device_id"
        name     = "DEVICE_ID"
        sql_type = "VARCHAR(64)"
      }
      record_columns {
        mapping  = "$.status"
        name     = "STATUS"
        sql_type = "VARCHAR(16)"
      }
      record_columns {
        mapping  = "$.temperature"
        name     = "TEMPERATURE"
        sql_type = "DOUBLE"
      }

      record_format {
        record_format_type = "JSON"
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }

  # SQL code to process the input stream
  code = <<EOT
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
    device_id VARCHAR(64), 
    status VARCHAR(16), 
    temperature DOUBLE
);

CREATE OR REPLACE PUMP "STREAM_PUMP" AS 
  INSERT INTO "DESTINATION_SQL_STREAM" 
  SELECT STREAM device_id, status, temperature 
  FROM "SOURCE_SQL_STREAM_001"
  WHERE temperature > 25.0;
EOT
}

