provider "aws" {
  region = "us-east-1"
}

# IAM Role for Kendra to access resources
resource "aws_iam_role" "kendra_role" {
  name = "kendra-data-source-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      },
    ]
  })
}

# Basic policy for Kendra Index and Data Source operations
resource "aws_iam_role_policy" "kendra_policy" {
  name = "kendra-policy"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kendra:BatchPutDocument",
          "kendra:BatchDeleteDocument"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# Kendra Index required for the Data Source
resource "aws_kendra_index" "example" {
  name     = "example-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"
}

# Kendra Data Source (Web Crawler type) with Proxy Configuration
resource "aws_kendra_data_source" "example_web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler-with-proxy"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = ["https://aws.amazon.com/"]
        }
      }

      # Proxy configuration block
      proxy_configuration {
        host = "proxy.example.com"
        port = 8080
        # Optional: Reference to an AWS Secrets Manager ARN containing proxy credentials
        # credentials = "arn:aws:secretsmanager:region:account-id:secret:secret-name"
      }

      # Optional crawl depth
      max_links_per_page = 100
      max_content_size_per_page_in_mega_bytes = 50
    }
  }

  description = "Web Crawler data source using a proxy server"
}

