}

# IAM Role for Kendra Index
resource "aws_iam_role" "kendra_role" {
  name = "kendra-data-source-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# Basic policy for Kendra to log to CloudWatch
resource "aws_iam_role_policy" "kendra_policy" {
  name = "kendra-policy"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Resource = "*"
      }
    ]
  })
}

# AWS Kendra Index
resource "aws_kendra_index" "example" {
  name     = "example-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"
}

# AWS Kendra Data Source (Web Crawler) with URL Inclusion and Exclusion Patterns
resource "aws_kendra_data_source" "web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = ["https://docs.aws.amazon.com/"]
          web_crawler_mode = "EVERYTHING"
        }
      }

      # URL Patterns use Regular Expressions
      # Inclusion: Only crawl pages containing "kendra" or "terraform"
      url_inclusion_patterns = [
        ".*kendra.*",
        ".*terraform.*"
      ]

      # Exclusion: Ignore any pages containing "archive" or ending in ".pdf"
      url_exclusion_patterns = [
        ".*archive.*",
        ".*\.pdf$"
      ]

      max_links_per_page = 100
      max_content_size_per_page_in_mega_bytes = 50
    }
  }

  tags = {
    Environment = "Production"
  }
}

