provider "aws" {
  region = "us-east-1"
}

# IAM Role for Kendra Index
resource "aws_iam_role" "kendra_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# Basic CloudWatch Logs policy for Kendra
resource "aws_iam_role_policy" "kendra_policy" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# Kendra Index with User Group Resolution
resource "aws_kendra_index" "example" {
  name        = "example-index"
  description = "Kendra index with AWS SSO user group resolution"
  edition     = "DEVELOPER_EDITION"
  role_arn    = aws_iam_role.kendra_role.arn

  # Configuration for resolving user groups using AWS IAM Identity Center (formerly AWS SSO)
  user_group_resolution_configuration {
    user_group_resolution_mode = "AWS_SSO"
  }

  tags = {
    Environment = "Development"
  }
}

