provider "aws" {
  region = "us-east-1"
}

resource "aws_route53_zone" "main" {
  name = "example.com"
}

resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = "primary-endpoint.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "primary_health_check"
  }
}

resource "aws_route53_health_check" "secondary_health_check" {
  fqdn              = "secondary-endpoint.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "secondary_health_check"
  }
}

# Active-Active configuration using Weighted Routing Policy
# This ensures both records are considered healthy and returned unless a health check fails.

resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "service.example.com"
  type    = "A"
  ttl     = "60"

  weighted_routing_policy {
    weight = 50
  }

  set_identifier  = "primary-active"
  health_check_id = aws_route53_health_check.primary_health_check.id
  records         = ["1.2.3.4"]
}

resource "aws_route53_record" "secondary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "service.example.com"
  type    = "A"
  ttl     = "60"

  weighted_routing_policy {
    weight = 50
  }

  set_identifier  = "secondary-active"
  health_check_id = aws_route53_health_check.secondary_health_check.id
  records         = ["5.6.7.8"]
}
```

