  name    = "example-failover-policy"
  comment = "Traffic policy to route traffic to secondary if primary is unhealthy"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-10-01"
    RecordType             = "A"
    Endpoints = {
      PrimaryRegion = {
        Type  = "value"
        Value = "192.0.2.1"
