terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.0"
    }
  }
}

variable "cluster_name" {
  description = "Name of the EKS cluster"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the Fargate profile"
  type        = list(string)
}

# Data sources for cluster details
data "aws_eks_cluster" "this" {
  name = var.cluster_name
}

data "aws_eks_cluster_auth" "this" {
  name = var.cluster_name
}

# IAM Role for EKS Fargate Pod Execution
resource "aws_iam_role" "fargate_pod_execution_role" {
  name = "${var.cluster_name}-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-12"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks-fargate-pods.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the necessary policy to the IAM role
resource "aws_iam_role_policy_attachment" "fargate_pod_execution_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.fargate_pod_execution_role.name
}

# Ensure subnets have the required resource tag for cluster association
resource "aws_ec2_tag" "subnet_cluster_tag" {
  for_each    = toset(var.subnet_ids)
  resource_id = each.value
  key         = "kubernetes.io/cluster/${var.cluster_name}"
  value       = "shared"
}

# AWS EKS Fargate Profile for kube-system
resource "aws_eks_fargate_profile" "kube_system" {
  cluster_name           = var.cluster_name
  fargate_profile_name   = "kube-system-profile"
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn
  subnet_ids             = var.subnet_ids

  selector {
    namespace = "kube-system"
  }

  depends_on = [aws_iam_role_policy_attachment.fargate_pod_execution_policy]
}

# Null resource to patch coredns deployment to remove the 'eks.amazonaws.com/compute-type: ec2' annotation
# so that it can run on Fargate nodes.
resource "null_resource" "patch_coredns" {
  triggers = {
    fargate_profile_arn = aws_eks_fargate_profile.kube_system.arn
  }

  provisioner "local-exec" {
    command = <<EOT
      kubectl patch deployment coredns \n        -n kube-system \n        --type json \n        -p='[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]' \n        --server=${data.aws_eks_cluster.this.endpoint} \n        --token=${data.aws_eks_cluster_auth.this.token} \n        --certificate-authority=<(echo "${data.aws_eks_cluster.this.certificate_authority[0].data}" | base64 -d)
    EOT
    interpreter = ["/bin/bash", "-c"]
  }

  depends_on = [aws_eks_fargate_profile.kube_system]
}

