provider "aws" {
  region = "us-east-1"
}

# AWS S3 bucket with forced destruction enabled
resource "aws_s3_bucket" "my_bucket" {
  bucket        = "my-unique-bucket-name-terraform-ai" # S3 bucket names must be globally unique
  force_destroy = true

  tags = {
    Name = "my_bucket"
  }
}

# S3 bucket metric for monitoring activity on the entire bucket
resource "aws_s3_bucket_metric" "my_bucket_metric" {
  bucket = aws_s3_bucket.my_bucket.id
  name   = "my_bucket_metric"
}

# S3 bucket object with specific key and content
resource "aws_s3_object" "my_object" {
  bucket  = aws_s3_bucket.my_bucket.id
  key     = "my_object_key.txt"
  content = "This is the content stored within my_object."

  tags = {
    Name = "my_object"
  }
}

