terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "infra_bucket" {
  bucket = "wellcomecollection-platform-infra"

  # Preventive destruction measure
  lifecycle {
    prevent_destroy = true
  }
}

# Ownership controls required to manage ACLs in modern AWS accounts
resource "aws_s3_bucket_ownership_controls" "infra_bucket_ownership" {
  bucket = aws_s3_bucket.infra_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Set bucket ACL to private
resource "aws_s3_bucket_acl" "infra_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.infra_bucket_ownership]

  bucket = aws_s3_bucket.infra_bucket.id
  acl    = "private"
}

# Enable versioning
resource "aws_s3_bucket_versioning" "infra_bucket_versioning" {
  bucket = aws_s3_bucket.infra_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Lifecycle configuration for tmp/ deletion and versioning management
resource "aws_s3_bucket_lifecycle_configuration" "infra_bucket_lifecycle" {
  depends_on = [aws_s3_bucket_versioning.infra_bucket_versioning]
  bucket     = aws_s3_bucket.infra_bucket.id

  # Rule 1: Delete objects with 'tmp/' prefix after 30 days
  rule {
    id     = "delete-tmp-objects"
    status = "Enabled"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }
  }

  # Rule 2: Manage noncurrent versions
  # Transition to STANDARD_IA after 30 days
  # Delete noncurrent versions after 90 days
  rule {
    id     = "manage-old-versions"
    status = "Enabled"

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

