extracted_code:
variable "bucket_suffix" {
  description = "The suffix for the S3 bucket names"
  type        = string
  default     = "test"
}

# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. CloudGoat Data Storage Bucket
resource "aws_s3_bucket" "cloudgoat_storage" {
  bucket = "cloudgoat-storage-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_ownership" {
  bucket = aws_s3_bucket.cloudgoat_storage.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_ownership]
  bucket     = aws_s3_bucket.cloudgoat_storage.id
  acl        = "private"
}

# 2. Web Data Storage Bucket
resource "aws_s3_bucket" "web_data_storage" {
  bucket = "web-data-storage-${var.bucket_suffix}"
}

# 3. Upload object 'order_data2.csv'
resource "aws_s3_object" "order_data" {
  bucket = aws_s3_bucket.web_data_storage.id
  key    = "order_data2.csv"
  source = "order_data2.csv" # Ensure this file exists in the local directory
}

# 4. Public Access Block for Web Data Bucket
resource "aws_s3_bucket_public_access_block" "web_data_pab" {
  bucket = aws_s3_bucket.web_data_storage.id

  block_public_acls       = true
  ignore_public_acls      = true
  restrict_public_buckets = true
  block_public_policy     = false # Must be false to allow the public bucket policy below
}

# 5. Bucket Policy for Web Data Bucket
resource "aws_s3_bucket_policy" "web_data_policy" {
  bucket = aws_s3_bucket.web_data_storage.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.web_data_storage.arn}/*"
      }
    ]
  })
}

