# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "bucket" {
  bucket = "your-bucket-name"
}

# 2. Create the SNS Topic
resource "aws_sns_topic" "topic" {
  name = "s3-event-notification-topic"
}

# 3. Define the IAM Policy Document for the SNS Topic
data "aws_iam_policy_document" "sns_topic_policy_doc" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    actions   = ["SNS:Publish"]
    resources = [aws_sns_topic.topic.arn]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = [aws_s3_bucket.bucket.arn]
    }
  }
}

# 4. Apply the Policy to the SNS Topic
resource "aws_sns_topic_policy" "default" {
  arn    = aws_sns_topic.topic.arn
  policy = data.aws_iam_policy_document.sns_topic_policy_doc.json
}

# 5. Configure S3 Bucket Notification to SNS
resource "aws_s3_bucket_notification" "bucket_notification" {
  bucket = aws_s3_bucket.bucket.id

  topic {
    topic_arn     = aws_sns_topic.topic.arn
    events        = ["s3:ObjectCreated:*"]
    filter_suffix = ".log"
  }

  # Ensure the SNS topic policy is applied before the S3 notification is created
  # to avoid "Access Denied" errors during bucket notification setup.
  depends_on = [aws_sns_topic_policy.default]
}

