provider "aws" {
  region = "us-east-1"
}

# S3 Bucket Definition
# Note: object_lock_enabled must be set to true at creation to use Object Lock
resource "aws_s3_bucket" "mybucket" {
  bucket              = "mybucket"
  object_lock_enabled = true

  tags = {
    Name = "mybucket"
  }
}

# Enable Versioning
resource "aws_s3_bucket_versioning" "mybucket_versioning" {
  bucket = aws_s3_bucket.mybucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Configure Object Lock Retention
resource "aws_s3_bucket_object_lock_configuration" "mybucket_lock" {
  bucket = aws_s3_bucket.mybucket.id

  rule {
    default_retention {
      mode = "COMPLIANCE"
      days = 5
    }
  }

  # Ensure versioning is fully applied before object lock configuration
  depends_on = [aws_s3_bucket_versioning.mybucket_versioning]
}

