# Terraform configuration for AWS VPC with Public/Private subnets 
# and 3 EC2 instances in a Cluster Placement Group.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-subnet"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# --- Compute & Clustering ---

# Placement Group with 'cluster' strategy for low-latency network performance
resource "aws_placement_group" "app_cluster" {
  name     = "app-cluster-pg"
  strategy = "cluster"
}

# Security Group for internal communication
resource "aws_security_group" "internal_sg" {
  name        = "allow_internal_traffic"
  description = "Allow all VPC internal traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Fetch latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]
  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# 3 EC2 Instances within the Placement Group
# Note: Cluster placement groups work best when instances are launched in the same subnet
resource "aws_instance" "cluster_nodes" {
  count         = 3
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.medium" # Instances must support enhanced networking

  subnet_id              = aws_subnet.private.id
  placement_group        = aws_placement_group.app_cluster.id
  vpc_security_group_ids = [aws_security_group.internal_sg.id]

  tags = {
    Name = "cluster-node-${count.index + 1}"
  }
}

