  region = "us-east-1"
}

# Create the Redshift cluster with 2 nodes
resource "aws_redshift_cluster" "this" {
  cluster_identifier      = "redshift-cluster-2-node"
  database_name           = "dev"
  master_username         = "adminuser"
  master_password         = "Password123!" # In production, use a secret manager or variable
  node_type               = "dc2.large"
  cluster_type            = "multi-node"
  number_of_nodes         = 2
  skip_final_snapshot     = true
  publicly_accessible     = false
}

# Limit concurrency scaling to 60 minutes
# Feature type "concurrency-scaling" supports limit_type "time" (measured in minutes)
resource "aws_redshift_usage_limit" "concurrency_limit" {
  cluster_identifier = aws_redshift_cluster.this.cluster_identifier
  feature_type       = "concurrency-scaling"
  limit_type         = "time"
  amount             = 60
  period             = "daily" # Options: daily, weekly, monthly
  breach_action      = "log"   # Options: log, emit-metric, disable
}

