provider "aws" {
  region = "us-east-1"
}

# Redshift Cluster configuration for a 1-node setup
resource "aws_redshift_cluster" "this" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "Password123!" # In production, use a secret manager or sensitive variable
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Basic retention must be > 0 to enable snapshots
  automated_snapshot_retention_period = 1

  skip_final_snapshot = true
}

# Define a snapshot schedule for every 12 hours
resource "aws_redshift_snapshot_schedule" "twelve_hours" {
  identifier  = "tf-redshift-snapshot-schedule-12h"
  definitions = ["rate(12 hours)"]
}

# Associate the custom schedule with the Redshift cluster
resource "aws_redshift_snapshot_schedule_association" "this" {
  cluster_identifier  = aws_redshift_cluster.this.id
  schedule_identifier = aws_redshift_snapshot_schedule.twelve_hours.id
}

