terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Primary Region Provider
provider "aws" {
  region = "us-east-1"
}

# Secondary Region Provider for Replication
provider "aws" {
  alias  = "us_east_2"
  region = "us-east-2"
}

# --- PRIMARY REGION (us-east-1) RESOURCES ---

resource "aws_vpc" "primary" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "primary_1" {
  vpc_id            = aws_vpc.primary.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "primary_2" {
  vpc_id            = aws_vpc.primary.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_redshift_subnet_group" "primary" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.primary_1.id, aws_subnet.primary_2.id]
}

resource "aws_kms_key" "primary" {
  description             = "KMS key for Redshift primary"
  deletion_window_in_days = 10
}

# --- SECONDARY REGION (us-east-2) RESOURCES ---

resource "aws_kms_key" "secondary" {
  provider                = aws.us_east_2
  description             = "KMS key for Redshift replica snapshots"
  deletion_window_in_days = 10
}

# Snapshot Copy Grant in the destination region is required for cross-region copy with KMS
resource "aws_redshift_snapshot_copy_grant" "secondary" {
  provider                 = aws.us_east_2
  snapshot_copy_grant_name = "redshift-copy-grant"
  kms_key_id               = aws_kms_key.secondary.arn
}

# --- REDSHIFT CLUSTER ---

resource "aws_redshift_cluster" "main" {
  cluster_identifier = "redshift-cluster-primary"
  database_name      = "maindb"
  master_username    = "adminuser"
  master_password    = "Password123!" # In production, use a secret manager or sensitive variable
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  cluster_subnet_group_name = aws_redshift_subnet_group.primary.name
  encrypted                 = true
  kms_key_id                = aws_kms_key.primary.arn

  # Cross-region snapshot replication configuration
  snapshot_copy {
    destination_region = "us-east-2"
    grant_name         = aws_redshift_snapshot_copy_grant.secondary.snapshot_copy_grant_name
    retention_period   = 7
  }

  skip_final_snapshot = true
}

