provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet_a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "redshift_subnet_b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_redshift_subnet_group" "redshift_sng" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_a.id, aws_subnet.redshift_subnet_b.id]

  tags = {
    Name = "My redshift subnet group"
  }
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Redshift Cluster ---

resource "aws_redshift_cluster" "this" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "Password123!" # In production, use a secret manager or variable
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  cluster_subnet_group_name    = aws_redshift_subnet_group.redshift_sng.name
  vpc_security_group_ids       = [aws_security_group.redshift_sg.id]
  skip_final_snapshot          = true
  publicly_accessible          = false
}

# --- Redshift Endpoint Access ---

resource "aws_redshift_endpoint_access" "this" {
  endpoint_name      = "redshift-managed-vpc-endpoint"
  cluster_identifier = aws_redshift_cluster.this.cluster_identifier
  subnet_group_name  = aws_redshift_subnet_group.redshift_sng.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}
