provider "aws" {
  region = "us-east-1"
}

# Lambda Function URL Resource
resource "aws_lambda_function_url" "example_lambda_url" {
  function_name      = aws_lambda_function.example_lambda.function_name
  authorization_type = "NONE"

  cors {
    allow_credentials = true
    allow_origins     = ["*"]
    allow_methods     = ["*"]
    allow_headers     = ["date", "keep-alive"]
    expose_headers    = ["keep-alive", "date"]
    max_age           = 86400
  }
}

# Permission to allow public access to the Function URL (since auth_type is NONE)
resource "aws_lambda_permission" "allow_public_url_access" {
  statement_id           = "AllowFunctionURLInvoke"
  action                 = "lambda:InvokeFunctionUrl"
  function_name          = aws_lambda_function.example_lambda.function_name
  principal              = "*"
  function_url_auth_type = "NONE"
}

# Referenced Lambda Function
resource "aws_lambda_function" "example_lambda" {
  function_name = "example_lambda"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
  filename      = "lambda_function_payload.zip" # Ensure this file exists or use a data source
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_exec_role" {
  name = "example_lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# Output the generated Function URL
output "function_url" {
  description = "The HTTP URL endpoint for the Lambda function"
  value       = aws_lambda_function_url.example_lambda_url.function_url
}

