  function_name = aws_lambda_function.example_lambda.function_name

  input = jsonencode({
    message = "Hello from Terraform"
  })

  # Note: By default, this triggers during terraform apply. 
  # To trigger on every apply, you can add a triggers map.
  triggers = {
    redeployment = sha1(jsonencode([
      aws_lambda_function.example_lambda.last_modified
    ]))
  }
}

