}

# CloudWatch Metric Alarm for EC2 CPU Utilization
resource "aws_cloudwatch_metric_alarm" "cpu_utilization_high" {
  alarm_name                = "high-cpu-utilization-alarm"
  comparison_operator       = "GreaterThanOrEqualToThreshold"
  evaluation_periods        = 2
  metric_name               = "CPUUtilization"
  namespace                 = "AWS/EC2"
  period                    = 300 # 5 minutes
  statistic                 = "Average"
  threshold                 = 80
  alarm_description         = "This metric monitors EC2 instance CPU utilization and triggers if it exceeds 80% for 2 consecutive periods."
  actions_enabled           = true
  alarm_actions             = [aws_sns_topic.alarm_topic.arn]
  ok_actions                = [aws_sns_topic.alarm_topic.arn]
  insufficient_data_actions = []

  dimensions = {
    InstanceId = "i-0123456789abcdef0"
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

