# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# DynamoDB Table definition
resource "aws_dynamodb_table" "main_table" {
  name           = "UserStatsTable"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "UserId"
  range_key      = "GameId"

  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "GameId"
    type = "S"
  }

  attribute {
    name = "Score"
    type = "N"
  }

  # Defining a Global Secondary Index (GSI)
  global_secondary_index {
    name               = "ScoreIndex"
    hash_key           = "Score"
    projection_type    = "ALL"
  }

  tags = {
    Environment = "Production"
    Name        = "UserStatsTable"
  }
}

# Enable Contributor Insights for the base DynamoDB table
resource "aws_dynamodb_contributor_insights" "table_insights" {
  table_name = aws_dynamodb_table.main_table.name
}

# Enable Contributor Insights for a specific Global Secondary Index (GSI)
resource "aws_dynamodb_contributor_insights" "gsi_insights" {
  table_name = aws_dynamodb_table.main_table.name
  index_name = "ScoreIndex"
}

