# DynamoDB Global Tables (Version 2019.11.21) are created by defining replica blocks
# within the aws_dynamodb_table resource. Stream must be enabled.
resource "aws_dynamodb_table" "global_table" {
  name             = "GlobalStoreTable"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "PK"
  range_key        = "SK"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "PK"
    type = "S"
  }

  attribute {
    name = "SK"
    type = "S"
  }

  # This creates a replica in the us-west-2 region
  replica {
    region_name = "us-west-2"
    propagate_tags = true
  }

  # This creates a replica in the eu-central-1 region
  replica {
    region_name = "eu-central-1"
    propagate_tags = true
  }

  tags = {
    Environment = "production"
    Terraform   = "true"
  }
}

