# IAM Role required for DAX to access DynamoDB
resource "aws_iam_role" "dax_role" {
  name = "dax-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      },
    ]
  })
}

# Attach policy to allow DAX full access to DynamoDB
resource "aws_iam_role_policy_attachment" "dax_policy" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDAXFullAccess"
}

# A Subnet Group is required for DAX clusters in a VPC
