      default_resource_spec {
        instance_type = "system"
      }
    }

    canvas_settings {
      time_series_forecasting_settings {
        status = "ENABLED"
      }
    }
  }

  tags = {
    Environment = "Dev"
    Department  = "DataScience"
  }
}
