# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# IAM Role for SageMaker Execution
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# Network Infrastructure for SageMaker Domain
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "sagemaker_subnet" {
  vpc_id     = aws_vpc.sagemaker_vpc.id
  cidr_block = "10.0.1.0/24"
}

# SageMaker Domain (Required for creating a Space)
resource "aws_sagemaker_domain" "example" {
  domain_name = "example-sagemaker-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = [aws_subnet.sagemaker_subnet.id]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn
  }
}

# SageMaker Space Resource
resource "aws_sagemaker_space" "example" {
  domain_id  = aws_sagemaker_domain.example.id
  space_name = "example-shared-space"

  space_settings {
    jupyter_server_app_settings {
      default_resource_spec {
        instance_type       = "system" # Default instance type for Jupyter Server
        sagemaker_image_arn = "arn:aws:sagemaker:us-east-1:081325390128:image/jupyter-server-3"
      }
    }

    # Optional: Configure Kernel Gateway settings
    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }
  }

  tags = {
    Environment = "Dev"
    Project     = "SageMaker-Spaces"
  }
}

