provider "aws" {
  region = "us-east-1"
}

# Fetch the ECR image URI for the built-in SageMaker kmeans algorithm
data "aws_sagemaker_prebuilt_ecr_image" "kmeans" {
  repository_name = "kmeans"
  image_tag       = "1" # Use version 1 of the kmeans algorithm
}

# IAM Role for SageMaker execution
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-kmeans-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach AmazonSageMakerFullAccess policy (standard for SageMaker models)
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Model definition
resource "aws_sagemaker_model" "kmeans_model" {
  name               = "kmeans-algorithm-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    image = data.aws_sagemaker_prebuilt_ecr_image.kmeans.registry_path
  }

  tags = {
    Name = "KMeansModel"
  }
}

