terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create an IAM Role for the SageMaker Notebook Instance
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker_notebook_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach the standard SageMaker full access policy to the role
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# Define the Git Repository resource in SageMaker
resource "aws_sagemaker_code_repository" "github_repo" {
  code_repository_name = "terraform-provider-aws-repo"

  git_config {
    repository_url = "https://github.com/hashicorp/terraform-provider-aws.git"
  }
}

# Create the SageMaker Notebook Instance linked to the Git Repository
resource "aws_sagemaker_notebook_instance" "notebook" {
  name                    = "terraform-aws-notebook"
  role_arn                = aws_iam_role.sagemaker_execution_role.arn
  instance_type           = "ml.t2.medium"
  default_code_repository = aws_sagemaker_code_repository.github_repo.code_repository_name

  tags = {
    Name = "TerraformProviderNotebook"
  }
}
```

