}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for SageMaker Pipeline execution
resource "aws_iam_role" "sagemaker_pipeline_role" {
  name = "sagemaker-pipeline-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach basic SageMaker access policy
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_pipeline_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Pipeline Resource
resource "aws_sagemaker_pipeline" "example" {
  pipeline_name         = "example-ml-pipeline"
  pipeline_display_name = "ExampleMachineLearningPipeline"
  role_arn              = aws_iam_role.sagemaker_pipeline_role.arn

  # The pipeline definition must be provided in SageMaker Pipeline Definition JSON format
  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Parameters = [
      {
        Name         = "ProcessingInstanceCount"
        Type         = "Integer"
        DefaultValue = 1
      },
      {
        Name         = "ProcessingInstanceType"
        Type         = "String"
        DefaultValue = "ml.m5.xlarge"
      }
    ]
    Steps = [
      {
        Name = "ExampleProcessingStep"
        Type = "Processing"
        Arguments = {
          ProcessingResources = {
            ClusterConfig = {
              InstanceCount = 1
              InstanceType  = "ml.m5.xlarge"
              VolumeSizeInGB = 30
            }
          }
          AppSpecification = {
            ImageUri = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"
            ContainerEntrypoint = ["python3", "/opt/ml/processing/input/code/preprocessing.py"]
          }
          RoleArn = aws_iam_role.sagemaker_pipeline_role.arn
        }
      }
    ]
  })

  tags = {
    Environment = "Development"
    Project     = "SageMaker-Automation"
  }
}

