# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# IAM Role for SageMaker
resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach SageMaker Full Access policy (for demonstration purposes)
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Model
resource "aws_sagemaker_model" "example_model" {
  name               = "example-sagemaker-model"
  execution_role_arn = aws_iam_role.sagemaker_role.arn

  primary_container {
    image = "127311923021.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3" # Example AWS managed image
  }
}

# SageMaker Endpoint Configuration
