extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lambda execution
resource "aws_iam_role" "iam_for_lambda" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# Standard policy for CloudWatch Logs access
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Create the deployment package
# Maps the local 'lambda.js' file to 'index.js' inside the zip to satisfy the handler requirement
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"

  source {
    content  = file("${path.module}/lambda.js")
    filename = "index.js"
  }
}

# AWS Lambda Function
resource "aws_lambda_function" "nodejs_lambda" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "my_nodejs_function"
  role             = aws_iam_role.iam_for_lambda.arn

  # 'index' refers to the filename 'index.js' inside the zip
  # 'handler' refers to the exported function within that file
  handler          = "index.handler"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime          = "nodejs18.x"

  environment {
    variables = {
      ENV = "development"
    }
  }

  depends_on = [
    aws_iam_role_policy_attachment.lambda_logs
  ]
}

# Optional: CloudWatch Log Group for the function
resource "aws_cloudwatch_log_group" "lambda_log_group" {
  name              = "/aws/lambda/${aws_lambda_function.nodejs_lambda.function_name}"
  retention_in_days = 7
}

