resource "aws_instance" "app_nodes" {
  count         = 3
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "c5.large"

  # Associate instances with the placement group
  placement_group = aws_placement_group.app_cluster_pg.id

  # Instances in a cluster placement group should ideally be in the same Availability Zone
  # For simplicity, this uses the default subnet of the provider's region/AZ

  tags = {
    Name = "Cluster-Node-${count.index + 1}"
  }
}

