# To reduce the number of database calls, we implement a caching layer using Amazon ElastiCache (Redis).
# This allows the application to store and retrieve frequently accessed data from memory instead of hitting the primary database.

resource "aws_security_group" "cache_sg" {
  name        = "cache-security-group"
  description = "Allow inbound traffic to Redis"

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC traffic
  }
}

resource "aws_elasticache_subnet_group" "main" {
  name       = "cache-subnet-group"
  subnet_ids = ["subnet-xxxxxxxx", "subnet-yyyyyyyy"] # Replace with actual subnet IDs
}

resource "aws_elasticache_replication_group" "db_cache" {
  replication_group_id          = "db-query-cache"
  replication_group_description = "Redis cluster to cache database queries and reduce load"
  node_type                     = "cache.t3.micro"
  port                          = 6379
  parameter_group_name          = "default.redis7"
  automatic_failover_enabled    = true
  multi_az_enabled              = true
  num_cache_clusters            = 2 # One primary, one replica for high availability
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.cache_sg.id]
  engine                        = "redis"
  engine_version                = "7.0"

  tags = {
    Environment = "production"
    Purpose     = "Reduce Database Latency and Call Volume"
  }
}

output "cache_endpoint" {
  description = "The endpoint of the Redis cache to be used by the application"
  value       = aws_elasticache_replication_group.db_cache.primary_endpoint_address
}

