# Terraform configuration to create an ElastiCache Redis User, User Group, 
# and a Replication Group with RBAC (Role-Based Access Control) authentication.

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the Redis user
resource "random_password" "redis_password" {
  length           = 32
  special          = false # Redis passwords often have restrictions on special characters in certain contexts
}

# Create the ElastiCache User
resource "aws_elasticache_user" "example_user" {
  user_id       = "example-user-id"
  user_name     = "exampleuser"
  engine        = "REDIS"
  access_string = "on ~* +@all" # Grant full access to all keys and commands (adjust as needed for least privilege)

  authentication_mode {
    type      = "password"
    passwords = [random_password.redis_password.result]
  }
}

# Create a User Group and assign the user to it
resource "aws_elasticache_user_group" "example_group" {
  engine        = "REDIS"
  user_group_id = "example-user-group"
  user_ids      = ["default", aws_elasticache_user.example_user.user_id] 
  # Note: The "default" user is required in every user group.
}

# Create a Redis Replication Group that uses the User Group for authentication
resource "aws_elasticache_replication_group" "example" {
  replication_group_id          = "example-redis-cluster"
  replication_group_description = "Redis cluster with RBAC authentication"
  node_type                     = "cache.t3.micro"
  num_cache_clusters            = 1
  port                          = 6379
  engine                        = "redis"
  engine_version                = "6.x" # RBAC requires Redis 6.0 or later

  # Associate the User Group
  user_group_ids = [aws_elasticache_user_group.example_group.user_group_id]

  # Mandatory for RBAC/User Groups
  transit_encryption_enabled = true

  lifecycle {
    ignore_changes = [num_cache_clusters]
  }
}

output "redis_user_password" {
  value     = random_password.redis_password.result
  sensitive = true
}

output "redis_endpoint" {
  value = aws_elasticache_replication_group.example.primary_endpoint_address
}

