# Terraform configuration to set up AWS ElastiCache (Redis) with IAM Authentication

provider "aws" {
  region = "us-east-1"
}

# 1. Define the ElastiCache User with IAM authentication
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-auth-user"
  user_name     = "iam_role_name" # This should match the name part of the IAM role/user mapping
  engine        = "REDIS"
  access_string = "on ~* +@all" # Full access, adjust as needed for production

  authentication_mode {
    type = "iam"
  }
}

# 2. Create a User Group and associate the IAM user
resource "aws_elasticache_user_group" "iam_user_group" {
  engine        = "REDIS"
  user_group_id = "iam-enabled-group"
  user_ids      = [aws_elasticache_user.iam_user.user_id, "default"] # 'default' user is required
}

# 3. Create the ElastiCache Replication Group (Transit Encryption is REQUIRED for IAM Auth)
resource "aws_elasticache_replication_group" "redis_cluster" {
  replication_group_id       = "iam-auth-cluster"
  description                = "Redis cluster with IAM authentication"
  node_type                  = "cache.t3.medium"
  num_cache_clusters         = 1
  port                       = 6379
  engine                     = "redis"
  engine_version             = "7.0"

  # IAM Authentication requirements:
  transit_encryption_enabled = true
  user_group_ids             = [aws_elasticache_user_group.iam_user_group.user_group_id]
}

# 4. IAM Policy to allow a specific identity to connect to the ElastiCache cluster
resource "aws_iam_policy" "elasticache_connect_policy" {
  name        = "ElastiCacheIAMConnectPolicy"
  description = "Allows connecting to ElastiCache using IAM credentials"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "elasticache:Connect"
        Effect   = "Allow"
        Resource = [aws_elasticache_user.iam_user.arn]
      }
    ]
  })
}

# Output the cluster endpoint
output "redis_endpoint" {
  value = aws_elasticache_replication_group.redis_cluster.primary_endpoint_address
}

