provider "aws" {
  region = "us-east-1"
}

# Create an ElastiCache User with password-based authentication (RBAC)
resource "aws_elasticache_user" "example_user" {
  user_id       = "example-user-id"
  user_name     = "exampleuser"
  engine        = "REDIS"
  access_string = "on ~* +@all" # Provides full access; restrict this for production environments

  authentication_mode {
    type      = "password"
    # You can provide multiple passwords to facilitate password rotation
    passwords = ["Password123!", "SecondaryPassword456!"]
  }
}

# ElastiCache users must belong to a User Group to be assigned to a Redis cluster
resource "aws_elasticache_user_group" "example_group" {
  engine        = "REDIS"
  user_group_id = "example-user-group"
  user_ids      = [
    "default", # The "default" user must be included in the user group
    aws_elasticache_user.example_user.user_id
  ]

  # Ensure the user is created before being added to the group
  depends_on = [aws_elasticache_user.example_user]
}

# Example Replication Group utilizing the User Group
# Note: Transit Encryption (TLS) MUST be enabled to use RBAC/Passwords
resource "aws_elasticache_replication_group" "example" {
  replication_group_id          = "example-cluster"
  replication_group_description = "Redis cluster with RBAC authentication"
  node_type                     = "cache.t4g.micro"
  num_cache_clusters            = 1
  port                          = 6379

  # Link the user group to the cluster
  user_group_ids              = [aws_elasticache_user_group.example_group.user_group_id]

  # Required settings for password authentication
  transit_encryption_enabled = true
  automatic_failover_enabled = true
}

