```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking for MSK ---

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnet_1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for Kafka"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    description = "Kafka Plaintext"
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  ingress {
    description = "Kafka TLS"
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Encryption Key ---

resource "aws_kms_key" "msk_kms_key" {
  description             = "KMS Key for MSK Cluster Encryption at Rest"
  deletion_window_in_days = 7
}

# --- MSK Cluster ---

resource "aws_msk_cluster" "managed_msk" {
  cluster_name           = "managed-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 2

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnet_1.id,
      aws_subnet.msk_subnet_2.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    # Encryption at rest using the customer managed KMS key
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms_key.arn

    # Encryption in transit (Optional but recommended)
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }

  tags = {
    Environment = "Production"
  }
}

resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "/aws/msk/managed-cluster"
}

output "zookeeper_connect_string" {
  value = aws_msk_cluster.managed_msk.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
  value = aws_msk_cluster.managed_msk.bootstrap_brokers_tls
}
```

