    Name = "msk-serverless-vpc"
  }
}

# MSK Serverless requires at least two subnets in different Availability Zones
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-subnet-b"
  }
}

# Security group for MSK (Port 9098 is used for IAM authentication)
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Security group for MSK Serverless Cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# MSK Serverless Cluster configuration
resource "aws_msk_serverless_cluster" "msk_serverless" {
  cluster_name = "serverless-msk-cluster"

  vpc_config {
    subnet_ids         = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  client_authentication {
    sasl {
      iam {
        enabled = true
      }
    }
  }

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

output "msk_cluster_arn" {
  value       = aws_msk_serverless_cluster.msk_serverless.arn
  description = "The Amazon Resource Name of the MSK Serverless Cluster"
}
