```hcl
# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# --- Networking ---
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-sg"
  vpc_id      = aws_vpc.msk_vpc.id
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

# --- Logging Destinations ---

# S3 Bucket for MSK logs and Custom Plugin storage
resource "aws_s3_bucket" "msk_storage" {
  bucket        = "msk-infrastructure-storage-bucket-${random_id.id.hex}"
  force_destroy = true
}

resource "random_id" "id" {
  byte_length = 4
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "/aws/msk/cluster-logs"
}

# Kinesis Firehose for MSK logs
resource "aws_iam_role" "firehose_role" {
  name = "firehose_msk_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "terraform-msk-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_storage.arn
  }
}

# --- MSK Cluster ---
resource "aws_kms_key" "msk_key" {
  description = "KMS key for MSK encryption"
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-debezium-cluster"
  kafka_version          = "3.2.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_storage.id
        prefix  = "logs/msk-"
      }
    }
  }
}

# --- MSK Connect ---

# Upload the plugin zip to S3 (Assumes debezium.zip exists in the same directory)
resource "aws_s3_object" "debezium_plugin_zip" {
  bucket = aws_s3_bucket.msk_storage.id
  key    = "plugins/debezium.zip"
  source = "debezium.zip" 
}

# Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-mysql-plugin"
  content_type = "ZIP"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_storage.arn
      file_key   = aws_s3_object.debezium_plugin_zip.key
    }
  }
}

# IAM Role for MSK Connector
resource "aws_iam_role" "connector_role" {
  name = "msk-connector-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "kafkaconnect.amazonaws.com" }
    }]
  })
}

# Connector Configuration
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-mysql-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max"                      = "1"
    "database.hostname"              = "change-me.rds.amazonaws.com"
    "database.port"                  = "3306"
    "database.user"                  = "debezium"
    "database.password"              = "password"
    "database.server.id"             = "184054"
    "database.server.name"           = "dbserver1"
    "database.include.list"          = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
    "database.history.kafka.topic"   = "dbhistory.inventory"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = aws_subnet.msk_subnets[*].id
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "IAM"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.connector_role.arn
}
