response:
```hcl
# Terraform Configuration for an AWS Aurora PostgreSQL Cluster

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-postgresql-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Aurora PostgreSQL Subnet Group"
  }
}

# --- Security Group ---

resource "aws_security_group" "aurora_sg" {
  name        = "aurora-postgresql-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to specific application CIDRs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Aurora PostgreSQL Cluster ---

resource "aws_rds_cluster" "postgresql_cluster" {
  cluster_identifier      = "aurora-postgresql-cluster"
  engine                  = "aurora-postgresql"
  engine_version          = "15.4"
  database_name           = "mydb"
  master_username         = "adminuser"
  master_password         = "SecurePassword123!" # Ideally use AWS Secrets Manager
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  db_subnet_group_name    = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.aurora_sg.id]
  skip_final_snapshot     = true
  storage_encrypted       = true

  tags = {
    Environment = "Dev"
    Project     = "AuroraPostgres"
  }
}

# --- Cluster Instances ---

resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = 2
  identifier         = "aurora-postgresql-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.postgresql_cluster.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.postgresql_cluster.engine
  engine_version     = aws_rds_cluster.postgresql_cluster.engine_version
  publicly_accessible = false

  tags = {
    Name = "Aurora PostgreSQL Instance ${count.index}"
  }
}

# --- Outputs ---

output "aurora_endpoint" {
  value = aws_rds_cluster.postgresql_cluster.endpoint
  description = "The cluster endpoint"
}

output "aurora_reader_endpoint" {
  value = aws_rds_cluster.postgresql_cluster.reader_endpoint
  description = "The cluster reader endpoint"
}
```

