# AWS RDS Multi-AZ DB Cluster (MySQL)
# This configuration creates a cluster with a primary and two readable standby instances 
# spread across three Availability Zones. The allocated_storage is provisioned 
# for each zone to ensure high availability and performance.
resource "aws_rds_cluster" "mysql_multi_az" {
  cluster_identifier      = "mysql-cluster-100gb"
  engine                  = "mysql"
  engine_version          = "8.0.35"

  # Provisioned storage for the cluster (replicated across 3 zones)
  allocated_storage       = 100
  storage_type            = "io1"
  iops                    = 3000

  # Multi-AZ DB Cluster requires a specific instance class
  db_cluster_instance_class = "db.m5d.large"

  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "ProvisionedPassword123!" # Use a Secret Manager in production

  db_subnet_group_name    = aws_db_subnet_group.mysql_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.mysql_sg.id]

  availability_zones      = ["us-east-1a", "us-east-1b", "us-east-1c"]
  skip_final_snapshot     = true

  tags = {
    Environment = "production"
    Storage     = "100GB-per-zone"
  }
}

