# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# IAM Role for DAX cluster to access DynamoDB
resource "aws_iam_role" "dax_role" {
  name = "dax-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      },
    ]
  })
}

# Policy allowing DAX to perform actions on DynamoDB
resource "aws_iam_role_policy" "dax_policy" {
  name = "dax-dynamodb-policy"
  role = aws_iam_role.dax_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "dynamodb:*"
        ]
        Effect   = "Allow"
        Resource = "*"
      },
    ]
  })
}

# Security Group for DAX (Default port is 8111)
resource "aws_security_group" "dax_sg" {
  name        = "dax-cluster-sg"
  description = "Security group for DAX cluster"
  vpc_id      = "vpc-12345678" # Replace with your actual VPC ID

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict to your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# DAX Subnet Group
resource "aws_dax_subnet_group" "dax_subnet_group" {
  name       = "dax-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with your actual Subnet IDs
}

# DAX Parameter Group (Optional, using default if not specified)
resource "aws_dax_parameter_group" "example" {
  name = "example-dax-pg"
  parameters {
    name  = "query-ttl-millis"
    value = "60000"
  }
}

# DAX Cluster
resource "aws_dax_cluster" "main" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.t3.medium"
  replication_factor = 3 # 1 primary + 2 replicas

  subnet_group_name  = aws_dax_subnet_group.dax_subnet_group.name
  security_group_ids = [aws_security_group.dax_sg.id]
  parameter_group_name = aws_dax_parameter_group.example.name

  maintenance_window = "sun:05:00-sun:09:00"

  tags = {
    Environment = "production"
    Name        = "DAX-Cluster"
  }
}

# Output the DAX Cluster Endpoint
output "dax_endpoint" {
  value       = aws_dax_cluster.main.configuration_endpoint
  description = "The configuration endpoint for the DAX cluster"
}

