# Terraform configuration for an AWS DynamoDB table with a custom Time to Live (TTL) attribute.
# Note: The TTL attribute in DynamoDB must store a timestamp in Unix epoch time format (seconds).

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_dynamodb_table" "ttl_enabled_table" {
  name           = "UserSessions"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "SessionId"

  attribute {
    name = "SessionId"
    type = "S"
  }

  # Custom TTL configuration
  # attribute_name: The name of the attribute used to store the expiration timestamp.
  # enabled: Whether TTL is enabled or disabled.
  ttl {
    attribute_name = "ExpiresAt"
    enabled        = true
  }

  tags = {
    Name        = "TTL-Enabled-Table"
    Environment = "Dev"
  }
}

