# Create a VPC
# Note: Egress-Only Internet Gateways are for IPv6 traffic, 
# so assign_generated_ipv6_cidr_block must be true.
resource "aws_vpc" "main" {
  cidr_block                       = "10.0.0.0/16"
  assign_generated_ipv6_cidr_block = true

  tags = {
    Name = "main-vpc"
  }
}

# Create the Egress-Only Internet Gateway
