  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-a"
  }
}

# Create the second subnet in Availability Zone B
resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-b"
  }
}

# Group the subnets together into a Neptune Subnet Group
resource "aws_neptune_subnet_group" "example" {
  name       = "example-neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Main Neptune Subnet Group"
  }
}
