provider "aws" {
  region = "us-east-1"
}

# 1. VPC and Networking
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-b"
  }
}

# 2. Neptune Subnet Group
resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name       = "neptune-main-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Neptune Subnet Group"
  }
}

# 3. Custom Neptune Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_params" {
  family      = "neptune1.2"
  name        = "custom-neptune-cluster-params"
  description = "Custom Neptune cluster parameter group"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# 4. Security Group restricting access to the two subnets
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-access-control"
  description = "Only allows connection from the two specified example subnets"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    # Restrict ingress only to the CIDR blocks of the two subnets defined above
    cidr_blocks = [
      aws_subnet.subnet_a.cidr_block,
      aws_subnet.subnet_b.cidr_block
    ]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Neptune Cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier                  = "neptune-cluster-demo"
  engine                              = "neptune"
  engine_version                      = "1.2.1.0"
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_params.name
  neptune_subnet_group_name           = aws_neptune_subnet_group.neptune_subnet_group.name
  vpc_security_group_ids              = [aws_security_group.neptune_sg.id]
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = true
  apply_immediately                   = true
}

# 6. Neptune Instance
resource "aws_neptune_cluster_instance" "neptune_instance" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.neptune_cluster.id
  engine             = "neptune"
  instance_class     = "db.t3.medium"
  apply_immediately  = true
}

