}

# Networking context for the Neptune Cluster
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "neptune_subnet_a" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "neptune_subnet_b" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# The "Example Subnet" that is allowed to connect
resource "aws_subnet" "client_subnet" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.10.0/24"
  availability_zone = "us-east-1a"
}

# Neptune Subnet Group
resource "aws_neptune_subnet_group" "neptune" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_a.id, aws_subnet.neptune_subnet_b.id]

  tags = {
    Name = "Neptune Subnet Group"
  }
}

# Security Group restricting access to the example subnet
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-access-sg"
  description = "Allow Neptune traffic from example subnet"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.client_subnet.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Custom Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_cluster_pg" {
  family      = "neptune1.2"
  name        = "custom-cluster-pg"
  description = "Custom neptune cluster parameter group"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# Custom Instance Parameter Group
resource "aws_neptune_parameter_group" "custom_instance_pg" {
  family      = "neptune1.2"
  name        = "custom-instance-pg"
  description = "Custom neptune instance parameter group"

  parameter {
    name  = "neptune_query_timeout"
    value = "20000"
  }
}

# Neptune Cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier                  = "neptune-cluster-demo"
  engine                              = "neptune"
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_cluster_pg.name
  neptune_subnet_group_name           = aws_neptune_subnet_group.neptune.name
  vpc_security_group_ids              = [aws_security_group.neptune_sg.id]
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = false
  apply_immediately                   = true
}

# Neptune Instance within the cluster
resource "aws_neptune_cluster_instance" "neptune_instance" {
  count                        = 1
  identifier                   = "neptune-instance-demo"
  cluster_identifier           = aws_neptune_cluster.neptune_cluster.id
  instance_class               = "db.t3.medium"
  neptune_parameter_group_name = aws_neptune_parameter_group.custom_instance_pg.name
  apply_immediately            = true
}

