# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create an Amazon Chime Voice Connector
# Voice Connectors must be created in us-east-1 or us-west-2
resource "aws_chime_voice_connector" "default" {
  name               = "streaming-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"
}

# Enable Media Streaming to Amazon Kinesis Video Streams
# When enabled, Chime automatically creates Kinesis Video Streams for each call
resource "aws_chime_voice_connector_streaming" "default" {
  voice_connector_id = aws_chime_voice_connector.default.id
  data_retention     = 24 # The number of hours to retain the streaming data in Kinesis
  disabled           = false

  # Optional: Define notification targets (SQS or SNS) to receive streaming events
  # streaming_notification_targets = ["SQS"]
}

# Optional: Enable Logging for the Voice Connector to monitor SIP and Media metrics
resource "aws_chime_voice_connector_logging" "default" {
  enable_media_metric_logs = true
  enable_sip_logs          = true
  voice_connector_id       = aws_chime_voice_connector.default.id
}

# Output the Voice Connector ID for reference
output "voice_connector_id" {
  value       = aws_chime_voice_connector.default.id
  description = "The ID of the Chime Voice Connector"
}

reference:
