extracted_code:
provider "aws" {
  region = "us-east-1"
}

# 1. Create AWS VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# 2. Create Two AWS Subnets
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# 3. Create AWS Redshift Subnet Group
resource "aws_redshift_subnet_group" "example" {
  name       = "example-redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "example-redshift-subnet-group"
  }
}

# 4. Create Security Group for Endpoint Access
resource "aws_security_group" "redshift_sg" {
  name   = "redshift-sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Create Example Basic AWS Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier         = "example-redshift-cluster"
  database_name              = "exampledb"
  master_username            = "admin"
  master_password            = "Password123!" # In production, use sensitive variables or Secrets Manager
  node_type                  = "dc2.large"
  cluster_type               = "single-node"
  cluster_subnet_group_name  = aws_redshift_subnet_group.example.name
  skip_final_snapshot        = true
  publicly_accessible        = false
}

# 6. Create AWS Redshift Endpoint Access
