# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Redshift Cluster
resource "aws_redshift_cluster" "this" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "exampledb"
  master_username    = "adminuser"
  master_password    = "Password123!" # In production, use a secret manager or variable
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  skip_final_snapshot = true
}

# SNS Topic for notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-event-notifications"
}

# SNS Topic Policy to allow Redshift to publish events
resource "aws_sns_topic_policy" "default" {
  arn = aws_sns_topic.redshift_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowRedshiftToPublish"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
        Action   = "sns:Publish"
        Resource = aws_sns_topic.redshift_notifications.arn
      }
    ]
  })
}

# Redshift Event Subscription
resource "aws_redshift_event_subscription" "this" {
  name          = "redshift-cluster-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_notifications.arn

  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.this.id]

  # Event categories include: configuration, management, monitoring, security
  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security"
  ]

  severity = "INFO"
  enabled  = true
}

# Output the SNS Topic ARN for subscription (e.g., Email or SMS)
output "sns_topic_arn" {
  value = aws_sns_topic.redshift_notifications.arn
}

