  cluster_identifier = "tf-redshift-cluster"
  database_name      = "dev"
  master_username    = "adminuser"
  master_password    = "Password123!" # In production, use a secret manager or sensitive variable
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Ensure the cluster is not deleted without a snapshot in production
  skip_final_snapshot = true
}

