terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Redshift Parameter Group with example parameters
resource "aws_redshift_parameter_group" "example" {
  name   = "example-redshift-parameter-group"
  family = "redshift-1.0"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  parameter {
    name  = "query_group"
    value = "default"
  }
}

# AWS Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier         = "example-cluster"
  database_name              = "exampledb"
  master_username            = "adminuser"
  master_password            = "Password123!" # In production, use a secret manager or variable
  node_type                  = "dc2.large"
  cluster_type               = "single-node"
  cluster_parameter_group_name = aws_redshift_parameter_group.example.name
  skip_final_snapshot        = true
}

# SNS Topic for notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-event-notifications"
}

# SNS Topic Policy to allow Redshift to publish events
resource "aws_sns_topic_policy" "default" {
  arn = aws_sns_topic.redshift_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid      = "AllowRedshiftPublish"
        Effect   = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.redshift_notifications.arn
      }
    ]
  })
}

# Redshift Event Subscription for Parameter Group events
resource "aws_redshift_event_subscription" "parameter_group_events" {
  name          = "redshift-parameter-group-subscription"
  sns_topic_arn = aws_sns_topic.redshift_notifications.arn

  source_type = "cluster-parameter-group"
  source_ids  = [aws_redshift_parameter_group.example.id]

  event_categories = [
    "configuration",
    "management"
  ]

  severity = "INFO"
  enabled  = true
}
```

