terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create the S3 Bucket
resource "aws_s3_bucket" "example" {
  bucket = "example-terraform-bucket-unique-id-12345"

  tags = {
    Name        = "Example Terraform Bucket"
    Environment = "Dev"
  }
}

# Manage ownership controls
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.example.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Block public access (Security Best Practice)
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.example.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Set ACL to private (requires ownership controls to be applied)
resource "aws_s3_bucket_acl" "example" {
  depends_on = [aws_s3_bucket_ownership_controls.example]

  bucket = aws_s3_bucket.example.id
  acl    = "private"
}
```

extracted_code:
provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for image storage
resource "aws_s3_bucket" "image_storage" {
  bucket = "my-website-images-${random_id.bucket_id.hex}"

  tags = {
    Name        = "Website Image Storage"
    Environment = "Production"
  }
}

# Random ID to ensure unique bucket name
resource "random_id" "bucket_id" {
  byte_length = 4
}

# Configure Ownership Controls to allow public access via ACLs/Policies
resource "aws_s3_bucket_ownership_controls" "image_storage_ownership" {
  bucket = aws_s3_bucket.image_storage.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Disable Public Access Block to allow the images to be served publicly
resource "aws_s3_bucket_public_access_block" "image_storage_public_access" {
  bucket = aws_s3_bucket.image_storage.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# Bucket Policy to allow public read access (GetObject) for website display
resource "aws_s3_bucket_policy" "public_read_access" {
  # Depends on the public access block being disabled
  depends_on = [aws_s3_bucket_public_access_block.image_storage_public_access]
  bucket     = aws_s3_bucket.image_storage.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.image_storage.arn}/*"
      }
    ]
  })
}

# CORS configuration to allow your website domain to fetch images
resource "aws_s3_bucket_cors_configuration" "image_storage_cors" {
  bucket = aws_s3_bucket.image_storage.id

  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET"]
    allowed_origins = ["*"] # For production, replace "*" with your actual domain (e.g., https://www.example.com)
    expose_headers  = ["ETag"]
    max_age_seconds = 3000
  }
}

output "bucket_name" {
  value = aws_s3_bucket.image_storage.id
}

output "bucket_endpoint" {
  value = "https://${aws_s3_bucket.image_storage.bucket_regional_domain_name}"
}

