provider "aws" {
  region = "us-east-1"
}

# Source S3 Bucket
resource "aws_s3_bucket" "source" {
  bucket = "mybucket"
}

# Destination S3 Bucket for Analytics Exports
resource "aws_s3_bucket" "destination" {
  bucket = "mybucket-analytics-results"
}

# Analytics Configuration
resource "aws_s3_bucket_analytics_configuration" "example" {
  # Reference to the source bucket ID
  bucket = aws_s3_bucket.source.id
  name   = "EntireBucketAnalytics"

  storage_class_analysis {
    data_export {
      destination {
        s3_bucket_destination {
          # Reference to the destination bucket ARN
          bucket_arn = aws_s3_bucket.destination.arn
          format     = "CSV"
        }
      }
    }
  }
}

# Required policy to allow S3 to write analytics data to the destination bucket
resource "aws_s3_bucket_policy" "allow_analytics_export" {
  bucket = aws_s3_bucket.destination.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowS3AnalyticsExport"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.destination.arn}/*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
          ArnLike = {
            "aws:SourceArn" = aws_s3_bucket.source.arn
          }
        }
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

