provider "aws" {
  region = "us-east-1"
}

# Main S3 Bucket
resource "aws_s3_bucket" "my_bucket" {
  bucket = "mybucket"
}

# Destination Bucket for Inventory Reports
resource "aws_s3_bucket" "inventory_destination" {
  bucket = "mybucket-inventory-destination"
}

# Policy to allow S3 to write inventory reports to the destination bucket
resource "aws_s3_bucket_policy" "inventory_destination_policy" {
  bucket = aws_s3_bucket.inventory_destination.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowInventoryToPutObjects"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.inventory_destination.arn}/*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
            "s3:x-amz-acl"      = "bucket-owner-full-control"
          }
        }
      }
    ]
  })
}

# Data source for account ID
data "aws_caller_identity" "current" {}

