  description             = "KMS key for S3 bucket server-side encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "s3-kms-key"
  }
}

# Create a KMS Alias for easier identification
resource "aws_kms_alias" "s3_key_alias" {
  name          = "alias/s3-encryption-key"
  target_key_id = aws_kms_key.s3_encryption_key.key_id
}

# Create the S3 Bucket
resource "aws_s3_bucket" "encrypted_bucket" {
  bucket = "my-secure-kms-encrypted-bucket-unique-id" # Ensure this bucket name is globally unique
}

# Apply Server-Side Encryption (SSE) configuration using the KMS key
resource "aws_s3_bucket_server_side_encryption_configuration" "sse_config" {
  bucket = aws_s3_bucket.encrypted_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.s3_encryption_key.arn
      sse_algorithm     = "aws:kms"
    }
    # Optional: Enable S3 Bucket Keys to reduce KMS request costs
    bucket_key_enabled = true
  }
}

