provider "aws" {
  region = "us-east-1"
}

# Create the S3 Bucket
resource "aws_s3_bucket" "static_website" {
  bucket = "my-terraform-website-bucket-example-unique-id" # Ensure this is globally unique
}

# Disable public access blocks to allow public read access for the website
resource "aws_s3_bucket_public_access_block" "website_access" {
  bucket = aws_s3_bucket.static_website.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# Define the Bucket Policy to allow public read access
resource "aws_s3_bucket_policy" "allow_public_read" {
  bucket = aws_s3_bucket.static_website.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.static_website.arn}/*"
      },
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.website_access]
}

# Configure the S3 Bucket for static website hosting
resource "aws_s3_bucket_website_configuration" "website_config" {
  bucket = aws_s3_bucket.static_website.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# Optional: Upload a basic index.html file
resource "aws_s3_object" "index" {
  bucket       = aws_s3_bucket.static_website.id
  key          = "index.html"
  content      = "<html><body><h1>Hello from Terraform</h1></body></html>"
  content_type = "text/html"
}

# Output the website URL
output "website_url" {
  value = aws_s3_bucket_website_configuration.website_config.website_endpoint
}

