```hcl
# Terraform configuration for a CS Autograder using AWS CodeBuild and S3

variable "github_repository_url" {
  description = "The URL of the GitHub repository containing the student code and buildspec."
  type        = string
  default     = "https://github.com/your-org/student-repo.git"
}

variable "github_token" {
  description = "GitHub Personal Access Token for CodeBuild to access the repository."
  type        = string
  sensitive   = true
}

# 1. S3 Bucket to store grading results and artifacts
resource "aws_s3_bucket" "autograder_results" {
  bucket_prefix = "cs-autograder-results-"
  force_destroy = true
}

resource "aws_s3_bucket_public_access_block" "autograder_results_block" {
  bucket                  = aws_s3_bucket.autograder_results.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for CodeBuild (Logging and S3 access)
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# 4. GitHub Credentials for CodeBuild
resource "aws_codebuild_source_credential" "github" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token
}

# 5. CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  description   = "Autograder project for computer science assignments"
  build_timeout = "10" # Minutes
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.autograder_results.bucket
    packaging = "ZIP"
    name      = "grading_result.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0" # Standard Ubuntu image with Python/Java/Node
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_ENV"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repository_url
    git_clone_depth = 1

    # Optional: Buildspec can be defined here or reside in the repo as 'buildspec.yml'
    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          commands:
            - echo Installing dependencies...
            - # e.g., pip install -r requirements.txt
        pre_build:
          commands:
            - echo Preparing environment...
        build:
          commands:
            - echo Running student tests...
            - # Run grading script here
            - python3 grader.py > results.json
        post_build:
          commands:
            - echo Grading complete.
      artifacts:
        files:
          - results.json
          - logs/**/*
    EOF
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-log-group"
      stream_name = "autograder-log-stream"
    }
  }

  tags = {
    Environment = "Education"
    Project     = "Autograder"
  }
}

# 6. Webhook to trigger on GitHub Pull Request or Push
resource "aws_codebuild_webhook" "autograder_webhook" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH, PULL_REQUEST_CREATED, PULL_REQUEST_UPDATED"
    }
  }
}

output "results_bucket_name" {
  value = aws_s3_bucket.autograder_results.id
}

output "codebuild_project_arn" {
  value = aws_codebuild_project.autograder.arn
}
```

