# Terraform configuration for a CS Autograder Infrastructure on AWS

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "github_repository_url" {
  description = "The URL of the student submission GitHub repository"
  type        = string
  default     = "https://github.com/example/student-repo.git"
}

# 1. S3 Bucket to store grading results and logs
resource "aws_s3_bucket" "autograder_results" {
  bucket        = "cs-autograder-results-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_public_access_block" "autograder_results_access" {
  bucket                  = aws_s3_bucket.autograder_results.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for CodeBuild to access S3 and CloudWatch Logs
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# 4. CloudWatch Log Group for autograder output
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 14
}

# 5. CodeBuild Project for running the autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-project"
  description   = "Autograder for CS class student submissions"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.autograder_results.id
    name     = "grading-output"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_ENV"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repository_url
    git_clone_depth = 1

    # Basic buildspec that runs tests and prepares results
    buildspec = <<EOF
version: 0.2
phases:
  install:
    commands:
      - echo Installing dependencies...
      - # pip install -r requirements.txt or equivalent
  pre_build:
    commands:
      - echo Preparing environment...
  build:
    commands:
      - echo Running autograder tests...
      - # python3 grader.py > results.json
  post_build:
    commands:
      - echo Grading completed on `date`
artifacts:
  files:
    - '**/*'
  base-directory: '.'
EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder_logs.name
      stream_name = "autograder-stream"
    }
  }

  tags = {
    Environment = "CS-Class"
  }
}

output "s3_bucket_name" {
  value = aws_s3_bucket.autograder_results.id
}

output "codebuild_project_arn" {
  value = aws_codebuild_project.autograder.arn
}
```

