# Terraform configuration for an isolated AWS CodeBuild Autograder
# This setup uses a VPC without an Internet Gateway to ensure code cannot reach the internet.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking (Isolated VPC) ---

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "isolated_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-isolated-subnet"
  }
}

# No Internet Gateway or NAT Gateway is created, ensuring isolation.

# --- Security Groups ---

resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Security group for autograder CodeBuild project"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Egress: No outbound internet access allowed.
  # We only allow traffic within the VPC if necessary, or to VPC Endpoints.
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  tags = {
    Name = "autograder-sg"
  }
}

# --- VPC Endpoints (Internal access to AWS Services) ---

# S3 Gateway Endpoint (to store results without internet)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids = [aws_vpc.autograder_vpc.main_route_table_id]
}

# Logs Interface Endpoint (to send logs to CloudWatch without internet)
resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.us-east-1.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.isolated_subnet.id]
  security_group_ids  = [aws_security_group.codebuild_sg.id]
  private_dns_enabled = true
}

# --- Storage ---

resource "aws_s3_bucket" "results" {
  bucket = "cs-autograder-results-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

# --- IAM Roles ---

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.results.arn,
          "${aws_s3_bucket.results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# --- CodeBuild Project ---

resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  description   = "Autograder that runs student code in isolation"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULT_BUCKET"
      value = aws_s3_bucket.results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo.git"
    git_clone_depth = 1
    buildspec       = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo "Running student tests..."
            - python3 grade_script.py > result.json
        post_build:
          commands:
            - aws s3 cp result.json s3://$RESULT_BUCKET/student-id/result.json
    EOF
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.isolated_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Environment = "Autograder"
  }
}

