# Terraform configuration for an isolated AWS-based Autograder
# This setup uses CodeBuild within a private VPC subnet without a NAT Gateway
# to ensure student code cannot reach the public internet during execution.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- VPC Networking (Isolating the environment) ---

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Routing table with NO Internet Gateway or NAT Gateway route
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-no-internet-rt"
  }
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private_subnet.id
  route_table_id = aws_route_table.private_rt.id
}

# --- VPC Endpoints (Allow CodeBuild to talk to AWS services internally) ---

resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.private_rt.id]
}

resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Allow internal traffic for autograder"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress rules to 0.0.0.0/0 effectively blocks internet access
  # Allow egress to VPC CIDR only for internal services if needed
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }
}

# --- Storage (S3 for results) ---

resource "aws_s3_bucket" "results" {
  bucket_prefix = "autograder-results-"
  force_destroy = true
}

resource "aws_s3_bucket_public_access_block" "results_block" {
  bucket = aws_s3_bucket.results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# --- IAM Roles for CodeBuild ---

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
