# Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

# VPC for isolation
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private Subnet with no Internet Gateway/NAT Gateway to prevent internet access
resource "aws_subnet" "autograder_private_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Route Table for the private subnet
resource "aws_route_table" "autograder_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-route-table"
  }
}

resource "aws_route_table_association" "autograder_rta" {
  subnet_id      = aws_subnet.autograder_private_subnet.id
  route_table_id = aws_route_table.autograder_rt.id
}

# Security Group: Allow internal VPC traffic, deny all outbound to 0.0.0.0/0
resource "aws_security_group" "autograder_sg" {
  name        = "autograder-sg"
  description = "Security group for autograder with no internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No ingress rules needed for autograder execution
  # No egress rule for 0.0.0.0/0 ensures no internet access

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
    description = "Allow traffic only within VPC"
  }

  tags = {
    Name = "autograder-sg"
  }
}

# VPC Endpoint for S3 (Gateway) - Allows CodeBuild to reach S3 without internet
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"
  vpc_endpoint_type = "Gateway"

  route_table_ids = [aws_route_table.autograder_rt.id]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# --- Storage ---

# S3 Bucket for storing autograder results
resource "aws_s3_bucket" "autograder_results" {
  bucket        = "cs-class-autograder-results-${random_id.id.hex}"
  force_destroy = true
}

resource "random_id" "id" {
  byte_length = 4
}

# --- IAM Roles ---

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for S3 access and VPC network interface management
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# --- Compute ---

# AWS CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Autograder project for student code"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULT_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-code-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_private_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  tags = {
    Environment = "Autograder"
  }
}

