# Terraform configuration for a Cat Picture API service using API Gateway and S3

provider "aws" {
  region = "us-east-1"
}

# --- S3 Storage ---
resource "aws_s3_bucket" "cat_storage" {
  bucket        = "cat-pictures-storage-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_public_access_block" "cat_storage_access" {
  bucket = aws_s3_bucket.cat_storage.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# --- IAM for Lambda ---
resource "aws_iam_role" "lambda_role" {
  name = "cat_service_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "lambda_s3_policy" {
  name = "cat_service_s3_policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["s3:PutObject", "s3:GetObject", "s3:ListBucket"]
        Effect   = "Allow"
        Resource = ["${aws_s3_bucket.cat_storage.arn}", "${aws_s3_bucket.cat_storage.arn}/*"]
      },
      {
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# --- Lambda Function Logic ---
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda.zip"
  source {
    filename = "index.js"
    content  = <<EOF
const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const BUCKET = process.env.BUCKET_NAME;

exports.handler = async (event) => {
    const path = event.path;
    const method = event.httpMethod;

    try {
        if (path === '/upload' && method === 'POST') {
            const fileContent = event.isBase64Encoded ? Buffer.from(event.body, 'base64') : event.body;
            const fileName = `cat_$${Date.now()}.jpg`;
            await s3.putObject({
                Bucket: BUCKET,
                Key: fileName,
                Body: fileContent,
                ContentType: 'image/jpeg'
            }).promise();
            return { statusCode: 200, body: JSON.stringify({ message: "Cat uploaded!", file: fileName }) };
        }

        if (path === '/random' && method === 'GET') {
            const data = await s3.listObjectsV2({ Bucket: BUCKET }).promise();
            if (!data.Contents || data.Contents.length === 0) {
                return { statusCode: 404, body: JSON.stringify({ message: "No cats found yet!" }) };
            }
            const randomIndex = Math.floor(Math.random() * data.Contents.length);
            const randomKey = data.Contents[randomIndex].Key;
            const url = s3.getSignedUrl('getObject', {
                Bucket: BUCKET,
                Key: randomKey,
                Expires: 60
            });
            return { statusCode: 302, headers: { Location: url } };
        }

        return { statusCode: 404, body: "Not Found" };
    } catch (err) {
        return { statusCode: 500, body: JSON.stringify(err) };
    }
};
EOF
  }
}

resource "aws_lambda_function" "cat_handler" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "cat_service_handler"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "nodejs18.x"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_storage.id
    }
  }
}

# --- API Gateway ---
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatPictureAPI"
  description = "API to upload and fetch random cat pictures"
}

resource "aws_api_gateway_resource" "proxy" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "{proxy+}"
}

resource "aws_api_gateway_method" "proxy_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.proxy.id
  http_method   = "ANY"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "lambda_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.proxy.id
  http_method             = aws_api_gateway_method.proxy_method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_handler.invoke_arn
}

resource "aws_api_gateway_deployment" "cat_api_deployment" {
  depends_on  = [aws_api_gateway_integration.lambda_integration]
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"
}

resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_handler.function_name
  principal     = "apigateway.amazonaws.com"
