# --- Lambda Function (Single function handling Logic) ---
# This Lambda serves the HTML UI, handles uploads, and fetches random images.
resource "aws_lambda_function" "cat_logic" {
  filename      = "lambda_function_payload.zip" # Assumes local zip or logic provided via data source
  function_name = "cat_logic_handler"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pics.id
    }
  }

  # Creating a dummy zip for structural validity
  # In a real scenario, use 'data.archive_file' or point to an existing zip
}

# --- API Gateway (REST API) ---
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatPictureAPI"
  description = "API for Cat Picture Web Server"
}

resource "aws_api_gateway_resource" "proxy" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "{proxy+}"
}

resource "aws_api_gateway_method" "proxy_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.proxy.id
  http_method   = "ANY"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "lambda_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.proxy.id
  http_method             = aws_api_gateway_method.proxy_method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_logic.invoke_arn
}

# Root path handling
resource "aws_api_gateway_method" "root_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  http_method   = "ANY"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "root_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_rest_api.cat_api.root_resource_id
  http_method             = aws_api_gateway_method.root_method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_logic.invoke_arn
}

# Deployment
resource "aws_api_gateway_deployment" "cat_api_deploy" {
  depends_on = [
    aws_api_gateway_integration.lambda_integration,
    aws_api_gateway_integration.root_integration
  ]
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
}

resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_api_deploy.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

# Permissions for API Gateway to invoke Lambda
resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_logic.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# --- Outputs ---
output "api_endpoint" {
  value       = aws_api_gateway_stage.prod.invoke_url
  description = "The URL of the Cat Picture Web Server"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_pics.id
}
