provider "aws" {
  region = "us-east-1"
}

# 1. Create an EC2 Instance
resource "aws_instance" "web_server" {
  ami           = "ami-0c101f26f147fa7fd" # Amazon Linux 2023 AMI (Update as needed)
  instance_type = "t3.micro"

  tags = {
    Name        = "DailyBackupInstance"
    BackupPolicy = "Daily"
  }
}

# 2. IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 3. AWS Backup Vault
resource "aws_backup_vault" "main_vault" {
  name = "ec2-backup-vault"
}

# 4. AWS Backup Plan (Scheduled for Midnight daily)
resource "aws_backup_plan" "daily_backup" {
  name = "daily-midnight-backup-plan"

  rule {
    rule_name         = "daily-midnight-rule"
    target_vault_name = aws_backup_vault.main_vault.name
    schedule          = "cron(0 0 * * ? *)" # Every day at 00:00 UTC

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

