# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Data source to fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]
  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# 1. Create the EC2 Instance
resource "aws_instance" "app_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  tags = {
    Name        = "DailyBackupInstance"
    BackupPolicy = "DailyMidnight"
  }
}

# 2. AWS Backup Vault
resource "aws_backup_vault" "ec2_backup_vault" {
  name = "ec2-instance-backup-vault"
}

# 3. AWS Backup Plan
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-midnight-backup-plan"

  rule {
    rule_name         = "daily-at-midnight"
    target_vault_name = aws_backup_vault.ec2_backup_vault.name
    schedule          = "cron(0 0 * * ? *)" # Midnight UTC every day

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# 4. IAM Role for AWS Backup
resource "aws_iam_role" "backup_service_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy for Backup Service
resource "aws_iam_role_policy_attachment" "backup_role_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_service_role.name
}

# 5. AWS Backup Selection (assigning resources to the plan via tags)
resource "aws_backup_selection" "ec2_backup_selection" {
  iam_role_arn = aws_iam_role.backup_service_role.arn
  name         = "daily-ec2-selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "BackupPolicy"
    value = "DailyMidnight"
  }
}
