# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# IAM Role for the Lambda Function
resource "aws_iam_role" "lambda_exec_role" {
  name = "daily_job_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# Basic execution policy for Lambda to log to CloudWatch
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# The Lambda Function (Assuming code is in a local file named 'lambda_function.zip')
resource "aws_lambda_function" "scheduled_task" {
  filename      = "lambda_function_payload.zip" # Ensure this file exists or use 'source_code_hash'
  function_name = "daily_7am_utc_task"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      ENV = "production"
    }
  }
}

# EventBridge Rule (Cron: 07:00 UTC every day)
# Format: cron(Minutes Hours Day-of-month Month Day-of-week Year)
resource "aws_cloudwatch_event_rule" "daily_at_seven" {
  name                = "daily-at-7am-utc"
  description         = "Triggers the Lambda function every day at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# EventBridge Target (Links Rule to Lambda)
resource "aws_cloudwatch_event_target" "invoke_lambda_at_seven" {
  rule      = aws_cloudwatch_event_rule.daily_at_seven.name
  target_id = "TriggerDailyLambda"
  arn       = aws_lambda_function.scheduled_task.arn
}

# Permission for EventBridge to invoke the Lambda Function
resource "aws_lambda_permission" "allow_eventbridge_to_call_lambda" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_task.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_at_seven.arn
}

