  type        = "zip"
  output_path = "lambda_function_payload.zip"
  source {
    content  = "def handler(event, context):
    print('Executing daily task at 7 UTC')
    return {'status': 'success'}"
    filename = "index.py"
  }
}

# --- Lambda Function ---
