# Terraform configuration for a global video streaming site using AWS CloudFront, S3, and Route53.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "domain_name" {
  type        = string
  description = "The domain name for the video streaming site (e.g., video.example.com)"
  default     = "video.example.com"
}

# 1. S3 Bucket for Video Content Storage
resource "aws_s3_bucket" "video_assets" {
  bucket = "video-streaming-assets-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "Video Assets Storage"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Block all public access to S3 (Access will be granted via OAC)
resource "aws_s3_bucket_public_access_block" "video_assets_block" {
  bucket = aws_s3_bucket.video_assets.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. CloudFront Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "video_oac" {
  name                              = "video_oac"
  description                       = "OAC for video streaming S3 bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 3. CloudFront Distribution
resource "aws_cloudfront_distribution" "video_distribution" {
  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video distribution"
  default_root_object = "index.html"

  # S3 Origin
  origin {
    domain_name              = aws_s3_bucket.video_assets.bucket_regional_domain_name
    origin_id                = "S3-VideoAssets"
    origin_access_control_id = aws_cloudfront_origin_access_control.video_oac.id
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-VideoAssets"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  # Global distribution via PriceClass_All
  price_class = "PriceClass_All"

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
    # If using a custom domain, configure acm_certificate_arn and ssl_support_method here
  }

  tags = {
    Environment = "production"
  }
}

# 4. S3 Bucket Policy to allow CloudFront OAC access
resource "aws_s3_bucket_policy" "video_assets_policy" {
  bucket = aws_s3_bucket.video_assets.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCloudFrontServicePrincipalReadOnly"
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_assets.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_distribution.arn
          }
        }
      }
    ]
  })
}

# 5. Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = var.domain_name
}

# 6. Route53 Alias Record pointing to CloudFront
resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = var.domain_name
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

output "cloudfront_domain_name" {
  value = aws_cloudfront_distribution.video_distribution.domain_name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.video_assets.id
}

