```hcl
# Terraform configuration for a Video Streaming Site Infrastructure on AWS

provider "aws" {
  region = "us-east-1"
}

# 1. VPC Module
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true

  tags = {
    Environment = "production"
    Application = "video-stream"
  }
}

# 2. Security Groups
resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "ec2_sg" {
  name        = "ec2-sg"
  description = "Allow traffic from ALB"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Application Load Balancer
resource "aws_lb" "video_alb" {
  name               = "video-streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets

  tags = {
    Name = "video-streaming-alb"
  }
}

# 4. Target Group
resource "aws_lb_target_group" "video_tg" {
  name     = "video-servers-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }
}

# 5. ALB Listener
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.video_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_tg.arn
  }
}

# 6. EC2 Instances
resource "aws_instance" "video_server" {
  count                  = 2
  ami                    = "ami-0c7217cdde317cfec" # Amazon Linux 2 (check region for validity)
  instance_type          = "t3.medium"
  subnet_id              = module.vpc.private_subnets[count.index]
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Stream Server ${count.index}</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "video-server-${count.index}"
  }
}

# 7. Target Group Attachment
resource "aws_lb_target_group_attachment" "video_tg_attachment" {
  count            = 2
  target_group_arn = aws_lb_target_group.video_tg.arn
  target_id        = aws_instance.video_server[count.index].id
  port             = 80
}

# 8. Route53 DNS Configuration
resource "aws_route53_zone" "main" {
  name = "mystreamingservice.com"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.mystreamingservice.com"
  type    = "A"

  alias {
    name                   = aws_lb.video_alb.dns_name
    zone_id                = aws_lb.video_alb.zone_id
    evaluate_target_health = true
  }
}
```

