      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random string for the DB instance identifier
resource "random_string" "db_id" {
  length  = 8
  special = false
  upper   = false
}

# Generate a random password for the master user
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Create the RDS instance with the random ID and password
resource "aws_db_instance" "rds_instance" {
  identifier           = "db-${random_string.db_id.result}"
  allocated_storage    = 20
  db_name              = "myappdb"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  username             = "admin"
  password             = random_password.db_password.result
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true
  publicly_accessible  = false

  tags = {
    Name = "GeneratedRDS"
  }
}

# Outputs to retrieve the generated information
output "rds_identifier" {
  description = "The randomly generated RDS identifier"
  value       = aws_db_instance.rds_instance.identifier
}

output "rds_password" {
  description = "The randomly generated RDS password"
  value       = random_password.db_password.result
  sensitive   = true
}

output "rds_endpoint" {
  description = "The connection endpoint"
  value       = aws_db_instance.rds_instance.endpoint
}
