  }
}

# Public Subnets (RDS requires subnets in at least two Availability Zones)
resource "aws_subnet" "public_a" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-a"
  }
}

resource "aws_subnet" "public_b" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-b"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public_a.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.public_b.id
  route_table_id = aws_route_table.public_rt.id
}

# DB Subnet Group
resource "aws_db_subnet_group" "db_subnets" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.public_a.id, aws_subnet.public_b.id]

  tags = {
    Name = "PostgreSQL DB subnet group"
  }
}

# Security Group for Database Access
resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Security group for PostgreSQL RDS"
  vpc_id      = aws_vpc.main.id

  # Ingress: PostgreSQL port 5432
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Recommendation: Restrict this to your specific IP range
  }

  # Egress: Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "db-security-group"
  }
}

# PostgreSQL RDS Instance
resource "aws_db_instance" "postgres" {
  identifier           = "postgres-db-instance"
  engine               = "postgres"
  engine_version       = "17.1"
  instance_class       = "db.t4g.micro"
  allocated_storage    = 5
  storage_type         = "standard" # "standard" (magnetic) supports 5GB; gp2/gp3 often require 20GB minimum
  db_name              = "myappdb"
  username             = "dbadmin"
  password             = "SecurePassword123!" # In production, use a secret manager or sensitive variable
  db_subnet_group_name = aws_db_subnet_group.db_subnets.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible  = true
  skip_final_snapshot  = true

  tags = {
    Environment = "Development"
  }
}

