# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

# Provision a VPC for the database
resource "aws_vpc" "database_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-secure-vpc"
  }
}

# Create Private Subnets in different AZs for Multi-AZ support
resource "aws_subnet" "private_subnet_a" {
  vpc_id            = aws_vpc.database_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "rds-private-subnet-a"
  }
}

resource "aws_subnet" "private_subnet_b" {
  vpc_id            = aws_vpc.database_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-private-subnet-b"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "postgresql_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_a.id, aws_subnet.private_subnet_b.id]

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# --- Security & Encryption ---

# KMS Key for RDS encryption at rest
resource "aws_kms_key" "rds_kms_key" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

resource "aws_kms_alias" "rds_kms_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_kms_key.key_id
}

# Security Group for the RDS Instance
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgres-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.database_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.database_vpc.cidr_block] # Restrict to VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-sg"
  }
}

# --- PostgreSQL Configuration ---

# Custom DB Parameter Group
resource "aws_db_parameter_group" "postgresql_pg" {
  name   = "custom-postgres15-pg"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "1"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres_db" {
  identifier = "secure-postgres-instance"

  # Engine specifications
  engine            = "postgres"
  engine_version    = "15.3"
  instance_class    = "db.t3.medium"
