  name        = "rds-postgres-sg"
  description = "Allow inbound traffic to PostgreSQL"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL access from within VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust based on your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-security-group"
  }
}

# Custom Parameter Group for PostgreSQL 15
resource "aws_db_parameter_group" "postgresql15_custom" {
  name   = "rds-pg15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "client_encoding"
    value = "utf8"
  }

  tags = {
    Name = "Custom PostgreSQL 15 Parameter Group"
  }
}

# RDS PostgreSQL Instance
