# Terraform configuration for a secure AWS RDS PostgreSQL instance

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Networking Infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "rds-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-subnet-b"
  }
}

resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# 2. Security Group for Database Access
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgres-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# 3. Encryption Key
resource "aws_kms_key" "rds_kms_key" {
  description             = "KMS key for RDS storage encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-encryption-key"
  }
}

# 4. Custom Parameter Group
resource "aws_db_parameter_group" "postgres_pg" {
  name   = "postgres15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "ssl"
    value = "1"
  }
}

# 5. RDS PostgreSQL Instance
resource "aws_db_instance" "postgres_db" {
  identifier           = "secure-postgresql-instance"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp3"
  db_name              = "myappdb"
  username             = "dbadmin"
  password             = "Password123!" # In production, use secret management like AWS Secrets Manager
  port                 = 5432

  # High Availability and Connectivity
  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  # Backup and Maintenance
  backup_retention_period = 7
  skip_final_snapshot     = true # Set to false for production

  # Encryption
  storage_encrypted = true
  kms_key_id        = aws_kms_key.rds_kms_key.arn

  # Configuration
  parameter_group_name = aws_db_parameter_group.postgres_pg.name

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}
