resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

resource "aws_kms_alias" "rds_key_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_key.key_id
}

# DB Subnet Group
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = var.private_subnet_ids

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# Security Group for the Database
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-rds-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = var.vpc_id

  ingress {
    description = "PostgreSQL port"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # Restrict to internal VPC range or specific CIDRs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-rds-sg"
  }
}

# Custom Parameter Group
resource "aws_db_parameter_group" "postgres_pg" {
  name   = "postgres15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "1"
  }
}

# PostgreSQL DB Instance
resource "aws_db_instance" "postgres_instance" {
  identifier                  = "secure-postgresql-db"
  engine                      = "postgres"
  engine_version              = "15.4"
  instance_class              = "db.t3.medium"
  allocated_storage           = 20
  max_allocated_storage       = 100
  storage_type                = "gp3"

  db_name                     = "myappdb"
  username                    = "dbadmin"
  password                    = var.db_password
  port                        = 5432

  # Network and Security
  db_subnet_group_name        = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.postgres_sg.id]
  publicly_accessible         = false
  multi_az                    = true

  # Encryption
  storage_encrypted           = true
  kms_key_id                  = aws_kms_key.rds_key.arn

  # Configuration and Maintenance
  parameter_group_name        = aws_db_parameter_group.postgres_pg.name
  backup_retention_period     = 7
  backup_window               = "03:00-04:00"
  maintenance_window          = "Mon:05:00-Mon:06:00"
  auto_minor_version_upgrade  = true
