# --- Networking ---

resource "aws_vpc" "airbyte_test_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "airbyte-test-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.airbyte_test_vpc.id
}

resource "aws_subnet" "public_1" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
}

resource "aws_subnet" "public_2" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.airbyte_test_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.public_2.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_db_subnet_group" "airbyte_pg_subnet_group" {
  name       = "airbyte-test-pg-subnet-group"
  subnet_ids = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  tags = {
    Name = "Airbyte Test DB Subnet Group"
  }
}

# --- Security ---

resource "aws_security_group" "rds_sg" {
  name        = "airbyte-test-rds-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.airbyte_test_vpc.id

  ingress {
    description = "PostgreSQL from anywhere (Testing Only)"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- RDS Instance ---

resource "aws_db_instance" "airbyte_pg_instance" {
  identifier           = "airbyte-connector-test-db"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  db_name              = "airbyte_test"
  username             = "airbyte_user"
  password             = "ReplaceWithSecurePassword123!" # Change in production/secrets manager

  # Managed settings for low maintenance
  publicly_accessible         = true
  db_subnet_group_name        = aws_db_subnet_group.airbyte_pg_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.rds_sg.id]

  auto_minor_version_upgrade  = true
  maintenance_window          = "Mon:03:00-Mon:04:00"
  backup_retention_period     = 7
  backup_window               = "01:00-02:00"
  copy_tags_to_snapshot       = true

  # Set to true for ephemeral test environments
  skip_final_snapshot         = true
  deletion_protection         = false

  tags = {
    Environment = "Testing"
    Project     = "Airbyte"
  }
}

output "rds_endpoint" {
  value = aws_db_instance.airbyte_pg_instance.endpoint
}
```

