# Terraform configuration for AWS RDS PostgreSQL 15
# Purpose: Airbyte connector test cases
# Settings: Managed, Low Maintenance, Publicly Accessible

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variable definitions for existing network infrastructure
variable "vpc_id" {
  type        = string
