  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restricted access recommended for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-test-db-sg"
  }
}

# DB Subnet Group using the specified public subnets
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = var.public_subnet_ids

