    auth_scheme = "SECRETS"
    description = "Secret-based auth for Aurora Proxy"
    iam_auth    = "DISABLED"
    secret_arn  = aws_secretsmanager_secret.db_creds.arn
  }
}

resource "aws_db_proxy_default_target_group" "proxy_tg" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent      = 100
    max_idle_connections_percent = 50
  }
