  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id
}

# --- Security Groups ---

resource "aws_security_group" "proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Allow inbound to Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "aurora_sg" {
  name        = "aurora-cluster-sg"
  description = "Allow inbound from Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy_sg.id]
  }
}

# --- Secrets Manager ---

resource "aws_secretsmanager_secret" "db_credentials" {
  name        = "aurora-db-credentials-v2"
  description = "Aurora MySQL credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username             = "admin"
    password             = "password12345" # In production, use a random provider
    engine               = "mysql"
    host                 = aws_rds_cluster.aurora.endpoint
    port                 = 3306
    dbClusterIdentifier  = aws_rds_cluster.aurora.cluster_identifier
  })
}

# --- IAM for RDS Proxy ---

resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "rds.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "proxy_policy" {
  name = "rds-proxy-secrets-policy"
  role = aws_iam_role.proxy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = ["secretsmanager:GetSecretValue", "secretsmanager:DescribeSecret"]
      Resource = [aws_secretsmanager_secret.db_credentials.arn]
    }]
  })
}

# --- Aurora MySQL Cluster ---

resource "aws_rds_cluster" "aurora" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.05.2"
