provider "aws" {
  region = "us-east-1"
}

# Create an Amazon Lightsail instance with dual-stack (IPv4 and IPv6) support
resource "aws_lightsail_instance" "dualstack_instance" {
  name              = "dualstack-lightsail-node"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # Set IP address type to dualstack for both IPv4 and IPv6
  ip_address_type   = "dualstack"

  tags = {
    Name        = "DualstackInstance"
    Environment = "Production"
  }
}

# Output the assigned IP addresses
output "lightsail_public_ipv4" {
  value       = aws_lightsail_instance.dualstack_instance.public_ip_address
  description = "The public IPv4 address of the Lightsail instance"
}

output "lightsail_ipv6_addresses" {
  value       = aws_lightsail_instance.dualstack_instance.ipv6_addresses
  description = "The assigned IPv6 addresses of the Lightsail instance"
}
