  region = "us-east-1"
}

# Generate a new SSH private key using the TLS provider
resource "tls_private_key" "lightsail_ssh" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Create a Lightsail Key Pair using the generated public key
resource "aws_lightsail_key_pair" "lightsail_key" {
  name       = "lightsail-custom-ssh-key"
  public_key = tls_private_key.lightsail_ssh.public_key_openssh
}

# Create a Lightsail Instance and associate the separate key pair
resource "aws_lightsail_instance" "web_server" {
  name              = "custom-key-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2" # Amazon Linux 2
  bundle_id         = "nano_2_0"       # Lowest tier bundle (CPU/RAM)
  key_pair_name     = aws_lightsail_key_pair.lightsail_key.name

  tags = {
    Name        = "LightsailWithCustomKey"
    Environment = "Production"
  }
}

