provider "aws" {
  region = "us-east-1"
}

# Create a managed AWS Lightsail Database
resource "aws_lightsail_database" "managed_db" {
  relational_database_name = "my-managed-database"
  availability_zone        = "us-east-1a"

  # Available Blueprints: mysql_8_0, postgres_15, postgres_14, etc.
  blueprint_id = "mysql_8_0"

  # Available Bundles: micro_1_0, small_1_0, medium_1_0, large_1_0
  bundle_id = "micro_1_0"

  master_database_name = "appdb"
  master_username      = "dbadmin"

  # Note: In a production environment, use a sensitive variable or a secret manager
  master_password      = "SecurePassword123!"

  # Configuration options
  backup_retention_enabled = true
  skip_final_snapshot      = true
  apply_immediately        = true
  publicly_accessible      = false

  tags = {
    Environment = "Development"
    Project     = "TerraformAI"
  }
}

# Output the database endpoint
output "lightsail_database_endpoint" {
  description = "The endpoint of the Lightsail database"
  value       = aws_lightsail_database.managed_db.master_endpoint_address
}

# Output the database port
output "lightsail_database_port" {
  description = "The port of the Lightsail database"
  value       = aws_lightsail_database.managed_db.master_endpoint_port
}

