provider "aws" {
  region = "us-east-1"
}

# Create the Lightsail Instance
resource "aws_lightsail_instance" "web_server" {
  name              = "web-server-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0" # Smallest tier for testing
  key_pair_name     = "my_key_pair" # Ensure this key pair exists in Lightsail
}

# Define the disks to be created
# Lightsail supports up to 15 additional disks per instance
variable "additional_disks" {
  default = {
    "disk1" = { size = 10, path = "/dev/xvdf" }
    "disk2" = { size = 20, path = "/dev/xvdg" }
  }
}

# Create the Lightsail Disks
resource "aws_lightsail_disk" "extra_storage" {
  for_each          = var.additional_disks
  name              = "storage-${each.key}"
  availability_zone = "us-east-1a" # Must be the same AZ as the instance
  size_in_gb        = each.value.size
}

# Attach the Disks to the Instance
resource "aws_lightsail_disk_attachment" "attachment" {
  for_each      = var.additional_disks
  disk_name     = aws_lightsail_disk.extra_storage[each.key].name
  instance_name = aws_lightsail_instance.web_server.name
  disk_path     = each.value.path
}

output "instance_public_ip" {
  value = aws_lightsail_instance.web_server.public_ip_address
}

