provider "aws" {
  region = "us-east-1"
}

# 1. Create the Lightsail Bucket to act as the origin
resource "aws_lightsail_bucket" "origin_bucket" {
  name      = "my-lightsail-origin-bucket"
  bundle_id = "small_1_0" # Choose appropriate bundle (e.g., small_1_0, medium_1_0)
}

# 2. Define the Lightsail Distribution
resource "aws_lightsail_distribution" "my_distribution" {
  name       = "my-lightsail-cdn"
  bundle_id  = "small_1_0" # Choose appropriate distribution bundle
  is_enabled = true

  # Configure the origin as the bucket created above
  origin {
    name          = aws_lightsail_bucket.origin_bucket.name
    region_name   = aws_lightsail_bucket.origin_bucket.region
    resource_type = "bucket"
  }

  # Default cache behavior settings
  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0

    forwarded_cookies {
      option = "none"
    }

    forwarded_headers {
      option = "none"
    }

    forwarded_query_strings {
      option = "false"
    }
  }
}

# 3. Grant the distribution access to the bucket
# This ensures the CDN has the necessary permissions to pull objects from the private bucket
resource "aws_lightsail_bucket_resource_access" "distribution_access" {
  bucket_name   = aws_lightsail_bucket.origin_bucket.name
  resource_name = aws_lightsail_distribution.my_distribution.name
}

output "distribution_url" {
  value       = aws_lightsail_distribution.my_distribution.domain_name
  description = "The public URL of the Lightsail Distribution"
}

