# AWS Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a Lightsail Instance to act as the Origin
resource "aws_lightsail_instance" "origin_instance" {
  name              = "origin-web-server"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"
}

# 2. Create a Lightsail Distribution
# Note: Bundle IDs for distributions typically include "small_1_0", "medium_1_0", or "large_1_0"
resource "aws_lightsail_distribution" "example_distribution" {
  name       = "example-cdn-distribution"
  bundle_id  = "small_1_0"
  is_enabled = true

  origin {
    name          = "primary-origin"
    region_name   = "us-east-1"
    resource_name = aws_lightsail_instance.origin_instance.name
    protocol_policy = "http-only" # Can be "http-only" or "https-only" depending on instance setup
  }

  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0

    forwarded_cookies {
      option = "none"
    }

    forwarded_headers {
      option = "none"
    }

    forwarded_query_strings {
      option = false
    }
  }

  # Optional: Configure custom cache behaviors if needed
  cache_behavior {
    path_pattern = "static/*"
    behavior     = "cache"
  }
}

# Output the Distribution URL
output "distribution_domain_name" {
  description = "The public domain name of the Lightsail distribution"
  value       = aws_lightsail_distribution.example_distribution.domain_name
}

