provider "aws" {
  region = "us-east-1"
}

# Create an SNS topic for Glacier vault notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-archive-notifications"
}

# Create the S3 Glacier Vault
resource "aws_glacier_vault" "archive_vault" {
  name = "long-term-data-archive-vault"

  notification {
    events   = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
    sns_topic = aws_sns_topic.glacier_notifications.arn
  }

  access_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowFullAccessToCreator"
        Effect = "Allow"
        Principal = {
          AWS = "*" # In production, restrict this to specific IAM roles or users
        }
        Action   = "glacier:*"
        Resource = "*"
      }
    ]
  })

  tags = {
    Environment = "Production"
    Purpose     = "LongTermArchiving"
    ManagedBy   = "Terraform"
  }
}

# Output the Vault ARN
output "glacier_vault_arn" {
  value       = aws_glacier_vault.archive_vault.arn
  description = "The ARN of the Glacier Vault"
}

