}

# 1. S3 Bucket for Long-Term Data with Lifecycle Rules
resource "aws_s3_bucket" "archive_bucket" {
  bucket = "long-term-archive-storage-${random_id.suffix.hex}"

  tags = {
    Name        = "LongTermArchive"
    Environment = "Production"
    Backup      = "True"
  }
}

resource "random_id" "suffix" {
  byte_length = 4
}

# Enable versioning for data protection
resource "aws_s3_bucket_versioning" "archive_versioning" {
  bucket = aws_s3_bucket.archive_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Lifecycle policy to transition data to Glacier Deep Archive for cost savings
resource "aws_s3_bucket_lifecycle_configuration" "archive_lifecycle" {
  bucket = aws_s3_bucket.archive_bucket.id

  rule {
    id     = "transition-to-deep-archive"
    status = "Enabled"

    # Move to Intelligent Tiering after 30 days
    transition {
      days          = 30
      storage_class = "INTELLIGENT_TIERING"
    }

    # Move to Glacier Deep Archive after 90 days for long-term storage
    transition {
      days          = 90
      storage_class = "DEEP_ARCHIVE"
    }

    # Optional: Delete old versions after 7 years (2555 days)
    noncurrent_version_expiration {
      noncurrent_days = 2555
    }
  }
}

# 2. AWS Backup Configuration for central management
resource "aws_backup_vault" "backup_vault" {
  name        = "long-term-backup-vault"
  kms_key_arn = null # Uses default AWS Backup KMS key if not specified
}

resource "aws_backup_plan" "long_term_backup_plan" {
  name = "daily-long-term-retention-plan"

  rule {
    rule_name         = "daily-backup-7-year-retention"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 5 * * ? *)" # Every day at 05:00 UTC

    lifecycle {
      cold_storage_after = 30   # Move to cold storage after 30 days
      delete_after       = 2555 # Keep for 7 years
    }
  }
}

# IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# Select resources to back up (based on tags or specific ARNs)
