  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "long-term-resource-selection"
  plan_id      = aws_backup_plan.long_term_backup_plan.id

  # Back up the S3 bucket and any other resource tagged with Backup=True
  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "True"
  }

  resources = [
    aws_s3_bucket.archive_bucket.arn
  ]
}

