provider "aws" {
  region = "us-east-1"
}

# 1. AWS S3 Glacier Vault
# This creates a dedicated Glacier Vault for direct archive storage.
resource "aws_glacier_vault" "my_archive_vault" {
  name = "backup-glacier-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  access_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowFullAccess"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "glacier:*"
        Resource = "arn:aws:glacier:us-east-1:*:vaults/backup-glacier-vault"
      }
    ]
  })

  tags = {
    Environment = "Production"
    Service     = "Glacier"
  }
}

resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-notifications-topic"
}

# 2. IAM Role for AWS Data Lifecycle Manager (DLM)
# DLM requires a role to manage snapshots on your behalf.
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "dlm_lifecycle_policy_auth" {
  name = "dlm-lifecycle-policy-auth"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:CreateSnapshots",
          "ec2:DeleteSnapshot",
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots",
          "ec2:CreateTags"
        ]
        Resource = "*"
      }
    ]
  })
}

# 3. AWS Data Lifecycle Manager (DLM) Lifecycle Policy
# This policy automates EBS snapshot creation. While DLM does not directly move files 
# into a specific Glacier Vault resource, it can move snapshots to the "Archive" tier 
# (which uses S3 Glacier storage) using the archive_rule.
resource "aws_dlm_lifecycle_policy" "ebs_to_glacier_policy" {
  description        = "Daily EBS snapshots with archival to Glacier tier"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    target_tags = {
      Snapshot = "true"
    }

    schedule {
      name = "Daily Snapshots"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["03:00"]
      }

      retain_rule {
        count = 7
      }

      # This transitions the snapshots to the Glacier Archive storage tier
      archive_rule {
        retain_rule {
          count = 1
        }
      }

      copy_tags = true
    }
  }
}

