terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# SNS Topic to receive notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-archive-retrieval-notifications"
}

# IAM Policy Document allowing Glacier to publish to the SNS topic
data "aws_iam_policy_document" "sns_glacier_policy" {
  statement {
    sid    = "AllowGlacierToPublish"
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["glacier.amazonaws.com"]
    }

    actions   = ["SNS:Publish"]
    resources = [aws_sns_topic.glacier_notifications.arn]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = ["arn:aws:glacier:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:vaults/my-archive-vault"]
    }
  }
}

# Attach the policy to the SNS Topic
resource "aws_sns_topic_policy" "default" {
  arn    = aws_sns_topic.glacier_notifications.arn
  policy = data.aws_iam_policy_document.sns_glacier_policy.json
}

# S3 Glacier Vault with Notification Configuration
resource "aws_glacier_vault" "archive_vault" {
  name = "my-archive-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  # Ensure the SNS policy is applied before the vault attempts to verify the SNS topic
  depends_on = [aws_sns_topic_policy.default]
}

# Data sources for dynamic account and region info
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

output "vault_arn" {
  value = aws_glacier_vault.archive_vault.arn
}

output "sns_topic_arn" {
  value = aws_sns_topic.glacier_notifications.arn
}

