# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Network Infrastructure ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "lb-forwarding-vpc"
  }
}

resource "aws_subnet" "public_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "public_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# --- Internal Network Load Balancer (The Backend) ---

resource "aws_lb" "internal_nlb" {
  name               = "internal-nlb"
  internal           = true
  load_balancer_type = "network"
  subnets            = [aws_subnet.public_a.id, aws_subnet.public_b.id]

  enable_cross_zone_load_balancing = true
}

resource "aws_lb_target_group" "nlb_tg" {
  name     = "nlb-target-group"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id

  health_check {
    protocol = "TCP"
    interval = 30
  }
}

resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.internal_nlb.arn
  port              = 80
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# --- Application Load Balancer (The Frontend) ---

resource "aws_security_group" "alb_sg" {
  name        = "alb-security-group"
  description = "Allow HTTP traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb" "external_alb" {
  name               = "external-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_a.id, aws_subnet.public_b.id]
}

# Note: To forward from ALB to NLB, the ALB Target Group must be of type 'alb' 
# or target the NLB's IP addresses. Here we use the 'alb' target type which 
# allows an ALB to directly point to another Load Balancer.
resource "aws_lb_target_group" "alb_to_nlb_tg" {
  name        = "alb-to-nlb-tg"
  target_type = "alb"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = aws_vpc.main.id

  health_check {
    enabled             = true
    protocol            = "HTTP"
    path                = "/"
    matcher             = "200-399"
  }
}

# Attach the NLB to the ALB's Target Group
resource "aws_lb_target_group_attachment" "alb_to_nlb" {
  target_group_arn = aws_lb_target_group.alb_to_nlb_tg.arn
  target_id        = aws_lb.internal_nlb.arn
  port             = 80
}

resource "aws_lb_listener" "alb_listener" {
  load_balancer_arn = aws_lb.external_alb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.alb_to_nlb_tg.arn
  }
}

# --- Outputs ---

output "alb_dns_name" {
  description = "The DNS name of the Application Load Balancer"
  value       = aws_lb.external_alb.dns_name
}

output "nlb_dns_name" {
  description = "The DNS name of the internal Network Load Balancer"
  value       = aws_lb.internal_nlb.dns_name
}

