# Terraform configuration for an AWS Application Load Balancer with OIDC Authentication

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "public_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 2. Security Group
resource "aws_security_group" "alb_sg" {
  name        = "allow_https"
  description = "Allow HTTPS inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Application Load Balancer
resource "aws_lb" "oidc_alb" {
  name               = "oidc-auth-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_1.id, aws_subnet.public_2.id]
}

# 4. Target Group (Forward destination after authentication)
resource "aws_lb_target_group" "app_tg" {
  name     = "oidc-app-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

# 5. HTTPS Listener with Authenticate-OIDC Action
# Note: Authenticate-OIDC requires HTTPS and a valid SSL certificate.
resource "aws_lb_listener" "https_listener" {
  load_balancer_arn = aws_lb.oidc_alb.arn
  port              = "443"
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/example-id" # Replace with valid ACM Cert ARN

  # First Action: Authenticate via OIDC provider (e.g., Okta, Auth0, Keycloak)
  default_action {
    type = "authenticate-oidc"

    authenticate_oidc {
      authorization_endpoint     = "https://example.com/oauth2/v1/authorize"
      client_id                  = "your-client-id"
      client_secret              = "your-client-secret"
      issuer                     = "https://example.com"
      token_endpoint             = "https://example.com/oauth2/v1/token"
      user_info_endpoint         = "https://example.com/oauth2/v1/userinfo"
      on_unauthenticated_request = "authenticate" # Options: authenticate, allow, deny
      session_cookie_name        = "AWSELBAuthSessionCookie"
      session_timeout            = 3600
      scope                      = "openid profile"
    }
  }

  # Second Action: Forward to Target Group after successful authentication
  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app_tg.arn
  }
}

