# AWS Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Network Infrastructure
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "gwlb-vpc"
  }
}

resource "aws_subnet" "gwlb_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "gwlb-subnet"
  }
}

# Gateway Load Balancer
resource "aws_lb" "gwlb" {
  name               = "production-gwlb"
  load_balancer_type = "gateway"
  subnets            = [aws_subnet.gwlb_subnet.id]

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

# Target Group for GENEVE protocol (Port 6081)
resource "aws_lb_target_group" "gwlb_tg" {
  name     = "gwlb-target-group"
  port     = 6081
  protocol = "GENEVE"
  vpc_id   = aws_vpc.main.id

  health_check {
    port     = "80"
    protocol = "TCP"
    interval = 10
  }
}

# Listener to route traffic to the Target Group
resource "aws_lb_listener" "gwlb_listener" {
  load_balancer_arn = aws_lb.gwlb.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.gwlb_tg.arn
  }
}

# VPC Endpoint Service (allows connecting the GWLB to other VPCs via Endpoints)
resource "aws_vpc_endpoint_service" "gwlb_service" {
  acceptance_required        = false
  gateway_load_balancer_arns = [aws_lb.gwlb.arn]

  tags = {
    Name = "gwlb-endpoint-service"
  }
}

# Output the Service Name for creating VPC Endpoints in consumer VPCs
output "gwlb_service_name" {
  value       = aws_vpc_endpoint_service.gwlb_service.service_name
  description = "The service name of the GWLB Endpoint Service to be used by consumers."
}

