# Example of a Memory-Optimized PostgreSQL instance on AWS RDS
# Using the R6g family (AWS Graviton2 memory-optimized instances)
resource "aws_db_instance" "memory_optimized_postgres" {
  identifier           = "memory-optimized-db"
  engine               = "postgres"
  engine_version       = "15.4"

  # Instance class: db.r6g.large provides a high memory-to-vCPU ratio (16GB RAM for 2 vCPUs)
  instance_class       = "db.r6g.large"

  allocated_storage    = 100
  max_allocated_storage = 500
  storage_type         = "gp3"

  db_name              = "application_db"
  username             = "db_admin"
  password             = "SecurePassword123!" # Recommended to use AWS Secrets Manager or Vault in production

  # Networking
  publicly_accessible  = false
  skip_final_snapshot  = true

  # Performance and Maintenance
  performance_insights_enabled          = true
  performance_insights_retention_period = 7
  backup_retention_period              = 7

  # Memory-specific parameter group tuning can be applied here
  parameter_group_name = "default.postgres15"

  tags = {
    Name        = "MemoryOptimizedPostgres"
    Workload    = "HighMemory"
    Environment = "Production"
  }
}

output "db_endpoint" {
  value = aws_db_instance.memory_optimized_postgres.endpoint
}

