# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# IAM Role to allow RDS to access the S3 bucket
resource "aws_iam_role" "rds_s3_import_role" {
  name = "rds-s3-import-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      },
    ]
  })
}

# IAM Policy to grant read access to the specific S3 bucket and objects
resource "aws_iam_policy" "rds_s3_import_policy" {
  name        = "rds-s3-import-policy"
  description = "Allows RDS to list and get objects from the backup bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:ListBucket",
          "s3:GetBucketLocation"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:s3:::my-db-backup-bucket"
      },
      {
        Action = [
          "s3:GetObject"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:s3:::my-db-backup-bucket/*"
      }
    ]
  })
}

# Attach the policy to the IAM role
resource "aws_iam_role_policy_attachment" "rds_s3_import_attach" {
  role       = aws_iam_role.rds_s3_import_role.name
  policy_arn = aws_iam_policy.rds_s3_import_policy.arn
}

# RDS Instance Restored from S3
# Note: The s3_import block is used to restore a MySQL or MariaDB database from S3 backup files.
resource "aws_db_instance" "restored_from_s3" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  identifier           = "my-restored-db-instance"
  username             = "admin"
  password             = "SecurePassword123!" # Recommended to use a secret management service
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true

  # Configuration for restoring from S3
  s3_import {
    source_engine         = "mysql"
    source_engine_version = "8.0"
    bucket_name           = "my-db-backup-bucket"
    bucket_prefix         = "backups/"
    ingestion_role        = aws_iam_role.rds_s3_import_role.arn
  }

  tags = {
    Name = "RestoredRDSFromS3"
  }
}

