# Terraform configuration to create an AWS RDS instance with Storage Autoscaling enabled

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Security group for the database
resource "aws_security_group" "db_sg" {
  name        = "database-sg"
  description = "Allow port 3306 for MySQL"

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict this to your VPC or specific CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Instance with Storage Autoscaling
resource "aws_db_instance" "rds_autoscaling" {
  identifier           = "autoscaling-db-instance"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  db_name              = "example_db"
  username             = "admin"
  password             = "Password123!" # It is recommended to use sensitive variables or Secrets Manager
  parameter_group_name = "default.mysql8.0"

  # Storage Configuration
  allocated_storage     = 20    # Initial storage in GB

  # Setting max_allocated_storage enables Storage Autoscaling. 
  # AWS will scale storage up to this limit when free space is low.
  max_allocated_storage = 100   

  storage_type          = "gp3"
  skip_final_snapshot   = true
  publicly_accessible   = false
  vpc_security_group_ids = [aws_security_group.db_sg.id]

  tags = {
    Name        = "Autoscaling-RDS-Instance"
    Environment = "Development"
  }
}

output "db_instance_endpoint" {
  value       = aws_db_instance.rds_autoscaling.endpoint
  description = "The connection endpoint for the RDS instance"
}

