# RDS Instance with Managed Master Password via Secrets Manager
resource "aws_db_instance" "default" {
  allocated_storage    = 20
  db_name              = "managed_db"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"

  # Enabling this manages the password in Secrets Manager automatically
  manage_master_user_password = true

  # When manage_master_user_password is true, leaving master_user_secret_kms_key_id 
  # empty defaults to the AWS managed key (aws/secretsmanager)
  master_user_secret_kms_key_id = null

  skip_final_snapshot = true
  publicly_accessible = false
}

# Output the Secret ARN created by RDS
output "db_password_secret_arn" {
  value       = aws_db_instance.default.master_user_secret[0].secret_arn
  description = "The ARN of the secret that contains the master user password"
}

