provider "aws" {
  region = "us-east-1"
}

# Create the EFS File System
resource "aws_efs_file_system" "example" {
  creation_token = "example-efs"
  encrypted      = true

  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  tags = {
    Name = "MyExampleEFS"
  }
}

# Apply an EFS File System Policy (System Policy)
# This example enforces SSL/TLS for all clients and grants read/mount permissions
resource "aws_efs_file_system_policy" "policy" {
  file_system_id = aws_efs_file_system.example.id

  policy = jsonencode({
    Version = "2012-10-17"
    Id      = "ExampleEFSSystemPolicy"
    Statement = [
      {
        Sid    = "EnforceSecureTransport"
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action   = "*"
        Resource = aws_efs_file_system.example.arn
        Condition = {
          Bool = {
            "aws:SecureTransport" = "false"
          }
        }
      },
      {
        Sid    = "AllowReadOnlyAccess"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientRead"
        ]
        Resource = aws_efs_file_system.example.arn
      }
    ]
  })
}

