# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC with IPv6 enabled
resource "aws_vpc" "main" {
  cidr_block                       = "10.0.0.0/16"
  assign_generated_ipv6_cidr_block = true

  tags = {
    Name = "main-vpc"
  }
}

# Create an Egress-Only Internet Gateway for the VPC
# This allows outbound IPv6 traffic while preventing inbound connections
resource "aws_egress_only_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-egress-only-gateway"
  }
}

# Create a route table that directs IPv6 traffic to the Egress-Only Internet Gateway
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    ipv6_cidr_block        = "::/0"
    egress_only_gateway_id = aws_egress_only_internet_gateway.main.id
  }

  tags = {
    Name = "private-route-table"
  }
}

# Example subnet to demonstrate association
resource "aws_subnet" "private" {
  vpc_id                          = aws_vpc.main.id
  cidr_block                      = "10.0.1.0/24"
  ipv6_cidr_block                 = cidrsubnet(aws_vpc.main.ipv6_cidr_block, 8, 1)
  assign_ipv6_address_on_creation = true

  tags = {
    Name = "private-subnet"
  }
}

# Associate the subnet with the route table containing the Egress-Only IGW route
resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

