extracted_code:
# Terraform configuration to create an AWS NAT Gateway
# associated with a specific subnet and Elastic IP allocation ID.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "subnet_id" {
  type        = string
  description = "The ID of the subnet in which to create the NAT Gateway."
}

variable "eip_allocation_id" {
  type        = string
  description = "The Allocation ID of the Elastic IP address for the NAT Gateway."
}

resource "aws_nat_gateway" "public_nat" {
  # The Allocation ID of the Elastic IP address for the gateway.
  allocation_id = var.eip_allocation_id

  # The Subnet ID of the subnet in which to place the gateway.
  subnet_id     = var.subnet_id

  # Connectivity type for the NAT Gateway. Valid values are 'public' and 'private'.
  # 'public' is the default and requires an allocation_id.
  connectivity_type = "public"

  tags = {
    Name = "MainNATGateway"
  }

  # Note: It is recommended to have an explicit dependency on the Internet Gateway 
  # for the VPC to ensure the NAT Gateway is created/destroyed in the correct order.
  # depends_on = [aws_internet_gateway.example]
}

output "nat_gateway_id" {
  value       = aws_nat_gateway.public_nat.id
  description = "The ID of the NAT Gateway."
}

output "nat_gateway_public_ip" {
  value       = aws_nat_gateway.public_nat.public_ip
  description = "The public IP address of the NAT Gateway."
}

